///Walk the immediate children of a [`SessionStatement`] node.
pub fn walk_session_statement<'ast, V, X>(visitor: &mut V, node: &'ast SessionStatement<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SessionStatement::Set {
            scope,
            name,
            assignment,
            value,
            meta,
        } => {
            if let Some(item) = scope.as_ref() {
                visitor.visit_set_scope(item);
            }
            visitor.visit_object_name(name);
            visitor.visit_set_assignment(assignment);
            visitor.visit_set_value(value);
            let _ = meta;
        }
        SessionStatement::SetTimeZone { scope, value, meta } => {
            if let Some(item) = scope.as_ref() {
                visitor.visit_set_scope(item);
            }
            visitor.visit_special_set_value(value);
            let _ = meta;
        }
        SessionStatement::SetRole { scope, role, meta } => {
            if let Some(item) = scope.as_ref() {
                visitor.visit_set_scope(item);
            }
            visitor.visit_special_set_value(role);
            let _ = meta;
        }
        SessionStatement::SetSessionAuthorization { scope, user, meta } => {
            if let Some(item) = scope.as_ref() {
                visitor.visit_set_scope(item);
            }
            visitor.visit_special_set_value(user);
            let _ = meta;
        }
        SessionStatement::SetConstraints {
            constraints,
            check_time,
            meta,
        } => {
            visitor.visit_constraints_target(constraints);
            visitor.visit_constraint_check_time(check_time);
            let _ = meta;
        }
        SessionStatement::SetNames { value, meta } => {
            visitor.visit_set_names_value(value);
            let _ = meta;
        }
        SessionStatement::SetSessionCharacteristics { modes, meta } => {
            for item in modes.iter() {
                visitor.visit_transaction_mode(item);
            }
            let _ = meta;
        }
        SessionStatement::Reset {
            scope,
            target,
            meta,
        } => {
            if let Some(item) = scope.as_ref() {
                visitor.visit_set_scope(item);
            }
            visitor.visit_config_parameter(target);
            let _ = meta;
        }
        SessionStatement::Show {
            target,
            verbose,
            meta,
        } => {
            visitor.visit_config_parameter(target);
            let _ = verbose;
            let _ = meta;
        }
        SessionStatement::SetVariables { assignments, meta } => {
            for item in assignments.iter() {
                visitor.visit_set_variable_assignment(item);
            }
            let _ = meta;
        }
        SessionStatement::SetCharacterSet {
            keyword,
            value,
            meta,
        } => {
            visitor.visit_character_set_keyword(keyword);
            visitor.visit_set_character_set_value(value);
            let _ = meta;
        }
        SessionStatement::SetResourceGroup {
            name,
            thread_ids,
            meta,
        } => {
            visitor.visit_ident(name);
            if let Some(item) = thread_ids.as_ref() {
                for item1 in item.iter() {
                    visitor.visit_literal(item1);
                }
            }
            let _ = meta;
        }
    }
}
