///Walk the immediate children of a [`AccessControlStatement`] node.
pub fn walk_access_control_statement<'ast, V, X>(
    visitor: &mut V,
    node: &'ast AccessControlStatement<X>,
) where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        AccessControlStatement::AlterRoleRename {
            name,
            new_name,
            meta,
        } => {
            visitor.visit_ident(name);
            visitor.visit_ident(new_name);
            let _ = meta;
        }
        AccessControlStatement::Grant {
            privileges,
            object,
            grantees,
            with_grant_option,
            granted_by,
            meta,
        } => {
            visitor.visit_privileges(privileges);
            visitor.visit_grant_object(object);
            for item in grantees.iter() {
                visitor.visit_grantee(item);
            }
            let _ = with_grant_option;
            if let Some(item) = granted_by.as_ref() {
                visitor.visit_role_spec(item);
            }
            let _ = meta;
        }
        AccessControlStatement::Revoke {
            grant_option_for,
            privileges,
            object,
            grantees,
            granted_by,
            behavior,
            meta,
        } => {
            let _ = grant_option_for;
            visitor.visit_privileges(privileges);
            visitor.visit_grant_object(object);
            for item in grantees.iter() {
                visitor.visit_grantee(item);
            }
            if let Some(item) = granted_by.as_ref() {
                visitor.visit_role_spec(item);
            }
            if let Some(item) = behavior.as_ref() {
                visitor.visit_drop_behavior(item);
            }
            let _ = meta;
        }
        AccessControlStatement::GrantRole {
            roles,
            grantees,
            with_admin_option,
            granted_by,
            meta,
        } => {
            for item in roles.iter() {
                visitor.visit_ident(item);
            }
            for item in grantees.iter() {
                visitor.visit_grantee(item);
            }
            let _ = with_admin_option;
            if let Some(item) = granted_by.as_ref() {
                visitor.visit_role_spec(item);
            }
            let _ = meta;
        }
        AccessControlStatement::RevokeRole {
            admin_option_for,
            roles,
            grantees,
            granted_by,
            behavior,
            meta,
        } => {
            let _ = admin_option_for;
            for item in roles.iter() {
                visitor.visit_ident(item);
            }
            for item in grantees.iter() {
                visitor.visit_grantee(item);
            }
            if let Some(item) = granted_by.as_ref() {
                visitor.visit_role_spec(item);
            }
            if let Some(item) = behavior.as_ref() {
                visitor.visit_drop_behavior(item);
            }
            let _ = meta;
        }
        AccessControlStatement::AccountGrantPrivilege {
            privileges,
            object,
            grantees,
            with_grant_option,
            grant_as,
            meta,
        } => {
            visitor.visit_privileges(privileges);
            visitor.visit_privilege_level_object(object);
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = with_grant_option;
            if let Some(item) = grant_as.as_ref() {
                visitor.visit_grant_as(item);
            }
            let _ = meta;
        }
        AccessControlStatement::AccountGrantProxy {
            proxy,
            grantees,
            with_grant_option,
            meta,
        } => {
            visitor.visit_account_name(proxy);
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = with_grant_option;
            let _ = meta;
        }
        AccessControlStatement::AccountGrantRole {
            roles,
            grantees,
            with_admin_option,
            meta,
        } => {
            for item in roles.iter() {
                visitor.visit_account_name(item);
            }
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = with_admin_option;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokePrivilege {
            if_exists,
            privileges,
            object,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            visitor.visit_privileges(privileges);
            visitor.visit_privilege_level_object(object);
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokeAll {
            if_exists,
            privileges_keyword,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            let _ = privileges_keyword;
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokeProxy {
            if_exists,
            proxy,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            visitor.visit_account_name(proxy);
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokeRole {
            if_exists,
            roles,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            for item in roles.iter() {
                visitor.visit_account_name(item);
            }
            for item in grantees.iter() {
                visitor.visit_account_name(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
    }
}
