///Walk the immediate children of a [`GrantObject`] node.
pub fn walk_grant_object<'ast, V, X>(visitor: &mut V, node: &'ast GrantObject<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        GrantObject::Table {
            explicit,
            names,
            meta,
        } => {
            let _ = explicit;
            for item in names.iter() {
                visitor.visit_object_name(item);
            }
            let _ = meta;
        }
        GrantObject::Named { kind, names, meta } => {
            visitor.visit_named_object_kind(kind);
            for item in names.iter() {
                visitor.visit_object_name(item);
            }
            let _ = meta;
        }
        GrantObject::Routines {
            kind,
            routines,
            meta,
        } => {
            visitor.visit_routine_object_kind(kind);
            for item in routines.iter() {
                visitor.visit_routine_signature(item);
            }
            let _ = meta;
        }
        GrantObject::AllInSchema {
            kind,
            schemas,
            meta,
        } => {
            visitor.visit_schema_object_kind(kind);
            for item in schemas.iter() {
                visitor.visit_object_name(item);
            }
            let _ = meta;
        }
    }
}
