///Walk the immediate children of a [`AuthOption`] node.
pub fn walk_auth_option<'ast, V, X>(visitor: &mut V, node: &'ast AuthOption)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        AuthOption::Password { password, meta } => {
            visitor.visit_literal(password);
            let _ = meta;
        }
        AuthOption::RandomPassword { meta } => {
            let _ = meta;
        }
        AuthOption::Plugin { plugin, meta } => {
            visitor.visit_ident(plugin);
            let _ = meta;
        }
        AuthOption::PluginAs {
            plugin,
            auth_string,
            meta,
        } => {
            visitor.visit_ident(plugin);
            visitor.visit_literal(auth_string);
            let _ = meta;
        }
        AuthOption::PluginByPassword {
            plugin,
            password,
            meta,
        } => {
            visitor.visit_ident(plugin);
            visitor.visit_literal(password);
            let _ = meta;
        }
        AuthOption::PluginByRandomPassword { plugin, meta } => {
            visitor.visit_ident(plugin);
            let _ = meta;
        }
    }
}
