///Walk the immediate children of a [`CreateTable`] node.
pub fn walk_create_table<'ast, V, X>(visitor: &mut V, node: &'ast CreateTable<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let CreateTable {
        or_replace,
        temporary,
        unlogged,
        if_not_exists,
        name,
        body,
        inherits,
        partition_by,
        access_method,
        options,
        meta,
    } = node;
    let _ = or_replace;
    if let Some(item) = temporary.as_ref() {
        visitor.visit_temporary_table_kind(item);
    }
    let _ = unlogged;
    let _ = if_not_exists;
    visitor.visit_object_name(name);
    visitor.visit_create_table_body(body);
    for item in inherits.iter() {
        visitor.visit_object_name(item);
    }
    if let Some(item) = partition_by.as_ref() {
        visitor.visit_partition_spec(item);
    }
    if let Some(item) = access_method.as_ref() {
        visitor.visit_ident(item);
    }
    for item in options.iter() {
        visitor.visit_create_table_option(item);
    }
    let _ = meta;
}
