///Walk the immediate children of a [`CreateTableBody`] node.
pub fn walk_create_table_body<'ast, V, X>(visitor: &mut V, node: &'ast CreateTableBody<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        CreateTableBody::Definition { elements, meta } => {
            for item in elements.iter() {
                visitor.visit_table_element(item);
            }
            let _ = meta;
        }
        CreateTableBody::AsQuery {
            columns,
            query,
            with_data,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            visitor.visit_query(query);
            let _ = with_data;
            let _ = meta;
        }
        CreateTableBody::AsExecute {
            columns,
            execute,
            with_data,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            visitor.visit_execute_statement(execute);
            let _ = with_data;
            let _ = meta;
        }
        CreateTableBody::PartitionOf {
            parent,
            elements,
            bound,
            meta,
        } => {
            visitor.visit_object_name(parent);
            for item in elements.iter() {
                visitor.visit_table_element(item);
            }
            visitor.visit_partition_bound(bound);
            let _ = meta;
        }
        CreateTableBody::OfType {
            type_name,
            elements,
            meta,
        } => {
            visitor.visit_object_name(type_name);
            for item in elements.iter() {
                visitor.visit_table_element(item);
            }
            let _ = meta;
        }
        CreateTableBody::LikeSource {
            source,
            parenthesized,
            meta,
        } => {
            visitor.visit_object_name(source);
            let _ = parenthesized;
            let _ = meta;
        }
    }
}
