///Walk the immediate children of a [`ColumnOption`] node.
pub fn walk_column_option<'ast, V, X>(visitor: &mut V, node: &'ast ColumnOption<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ColumnOption::Null { meta } => {
            let _ = meta;
        }
        ColumnOption::NotNull { meta } => {
            let _ = meta;
        }
        ColumnOption::Default { expr, meta } => {
            visitor.visit_expr(expr);
            let _ = meta;
        }
        ColumnOption::Generated { generated, meta } => {
            visitor.visit_generated_column(generated);
            let _ = meta;
        }
        ColumnOption::Identity { identity, meta } => {
            visitor.visit_identity_column(identity);
            let _ = meta;
        }
        ColumnOption::PrimaryKey {
            ascending,
            index_tablespace,
            meta,
        } => {
            let _ = ascending;
            if let Some(item) = index_tablespace.as_ref() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        ColumnOption::Unique {
            nulls_not_distinct,
            index_tablespace,
            meta,
        } => {
            let _ = nulls_not_distinct;
            if let Some(item) = index_tablespace.as_ref() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        ColumnOption::AutoIncrement { spelling, meta } => {
            visitor.visit_auto_increment_spelling(spelling);
            let _ = meta;
        }
        ColumnOption::Collate { collation, meta } => {
            visitor.visit_object_name(collation);
            let _ = meta;
        }
        ColumnOption::Check {
            expr,
            no_inherit,
            meta,
        } => {
            visitor.visit_expr(expr);
            let _ = no_inherit;
            let _ = meta;
        }
        ColumnOption::References { reference, meta } => {
            visitor.visit_foreign_key_ref(reference);
            let _ = meta;
        }
        ColumnOption::Bare { meta } => {
            let _ = meta;
        }
        ColumnOption::Other { ext, meta } => {
            visitor.visit_extension(ext);
            let _ = meta;
        }
    }
}
