///Walk the immediate children of a [`TableConstraint`] node.
pub fn walk_table_constraint<'ast, V, X>(visitor: &mut V, node: &'ast TableConstraint<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TableConstraint::PrimaryKey {
            columns,
            include,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_index_column(item);
            }
            for item in include.iter() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        TableConstraint::Unique {
            columns,
            nulls_not_distinct,
            include,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_index_column(item);
            }
            let _ = nulls_not_distinct;
            for item in include.iter() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        TableConstraint::Check { expr, meta } => {
            visitor.visit_expr(expr);
            let _ = meta;
        }
        TableConstraint::Exclude { exclude, meta } => {
            visitor.visit_exclude_constraint(exclude);
            let _ = meta;
        }
        TableConstraint::ForeignKey {
            columns,
            references,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            visitor.visit_foreign_key_ref(references);
            let _ = meta;
        }
        TableConstraint::Bare { meta } => {
            let _ = meta;
        }
        TableConstraint::Other { ext, meta } => {
            visitor.visit_extension(ext);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a [`ExcludeConstraint`] node.
pub fn walk_exclude_constraint<'ast, V, X>(visitor: &mut V, node: &'ast ExcludeConstraint<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let ExcludeConstraint {
        method,
        elements,
        include,
        with_params,
        index_tablespace,
        predicate,
        meta,
    } = node;
    if let Some(item) = method.as_ref() {
        visitor.visit_ident(item);
    }
    for item in elements.iter() {
        visitor.visit_exclude_element(item);
    }
    for item in include.iter() {
        visitor.visit_ident(item);
    }
    for item in with_params.iter() {
        visitor.visit_table_storage_parameter(item);
    }
    if let Some(item) = index_tablespace.as_ref() {
        visitor.visit_ident(item);
    }
    if let Some(item) = predicate.as_ref() {
        visitor.visit_expr(item);
    }
    let _ = meta;
}
///Walk the immediate children of a [`ExcludeElement`] node.
pub fn walk_exclude_element<'ast, V, X>(visitor: &mut V, node: &'ast ExcludeElement<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let ExcludeElement {
        expr,
        parenthesized,
        collation,
        opclass,
        opclass_params,
        asc,
        nulls_first,
        operator,
        meta,
    } = node;
    visitor.visit_expr(expr);
    let _ = parenthesized;
    if let Some(item) = collation.as_ref() {
        visitor.visit_object_name(item);
    }
    if let Some(item) = opclass.as_ref() {
        visitor.visit_object_name(item);
    }
    for item in opclass_params.iter() {
        visitor.visit_table_storage_parameter(item);
    }
    let _ = asc;
    let _ = nulls_first;
    visitor.visit_exclude_operator(operator);
    let _ = meta;
}
///Walk the immediate children of a [`ExcludeOperator`] node.
pub fn walk_exclude_operator<'ast, V, X>(visitor: &mut V, node: &'ast ExcludeOperator)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let ExcludeOperator {
        schema,
        op,
        spelling,
    } = node;
    visitor.visit_object_name(schema);
    let _ = op;
    visitor.visit_named_operator_spelling(spelling);
}
