///Walk the immediate children of a [`CreateTableOptionKind`] node.
pub fn walk_create_table_option_kind<'ast, V, X>(
    visitor: &mut V,
    node: &'ast CreateTableOptionKind<X>,
) where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        CreateTableOptionKind::ColocateWith {
            table,
            columns,
            meta,
        } => {
            visitor.visit_object_name(table);
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        CreateTableOptionKind::InColocationGroup {
            group,
            columns,
            meta,
        } => {
            visitor.visit_ident(group);
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        CreateTableOptionKind::With { params, meta } => {
            for item in params.iter() {
                visitor.visit_table_storage_parameter(item);
            }
            let _ = meta;
        }
        CreateTableOptionKind::OnCommit { action, meta } => {
            visitor.visit_on_commit_action(action);
            let _ = meta;
        }
        CreateTableOptionKind::Tablespace { tablespace, meta } => {
            visitor.visit_ident(tablespace);
            let _ = meta;
        }
        CreateTableOptionKind::KeyValue { option, meta } => {
            visitor.visit_table_option(option);
            let _ = meta;
        }
        CreateTableOptionKind::WithoutRowid { meta } => {
            let _ = meta;
        }
        CreateTableOptionKind::Strict { meta } => {
            let _ = meta;
        }
        CreateTableOptionKind::WithoutOids { meta } => {
            let _ = meta;
        }
    }
}
