///Walk the immediate children of a [`ObjectReference`] node.
pub fn walk_object_reference<'ast, V, X>(visitor: &mut V, node: &'ast ObjectReference<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ObjectReference::Named { kind, name, meta } => {
            visitor.visit_object_ref_kind(kind);
            visitor.visit_object_name(name);
            let _ = meta;
        }
        ObjectReference::Routine {
            kind,
            signature,
            meta,
        } => {
            visitor.visit_routine_object_kind(kind);
            visitor.visit_routine_signature(signature);
            let _ = meta;
        }
        ObjectReference::Aggregate { name, args, meta } => {
            visitor.visit_object_name(name);
            visitor.visit_aggregate_args(args);
            let _ = meta;
        }
        ObjectReference::Operator {
            schema,
            op,
            args,
            meta,
        } => {
            visitor.visit_object_name(schema);
            let _ = op;
            visitor.visit_operator_args(args);
            let _ = meta;
        }
        ObjectReference::OperatorClass {
            family,
            name,
            access_method,
            meta,
        } => {
            let _ = family;
            visitor.visit_object_name(name);
            visitor.visit_ident(access_method);
            let _ = meta;
        }
        ObjectReference::Cast { from, to, meta } => {
            visitor.visit_data_type(from);
            visitor.visit_data_type(to);
            let _ = meta;
        }
        ObjectReference::Type { domain, name, meta } => {
            let _ = domain;
            visitor.visit_data_type(name);
            let _ = meta;
        }
        ObjectReference::Transform {
            type_name,
            language,
            meta,
        } => {
            visitor.visit_data_type(type_name);
            visitor.visit_ident(language);
            let _ = meta;
        }
        ObjectReference::Trigger { name, table, meta } => {
            visitor.visit_ident(name);
            visitor.visit_object_name(table);
            let _ = meta;
        }
    }
}
