///Walk the immediate children of a [`AlterInstanceAction`] node.
pub fn walk_alter_instance_action<'ast, V, X>(visitor: &mut V, node: &'ast AlterInstanceAction)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        AlterInstanceAction::RotateInnodbMasterKey { meta } => {
            let _ = meta;
        }
        AlterInstanceAction::RotateBinlogMasterKey { meta } => {
            let _ = meta;
        }
        AlterInstanceAction::ReloadTls {
            channel,
            no_rollback_on_error,
            meta,
        } => {
            if let Some(item) = channel.as_ref() {
                visitor.visit_ident(item);
            }
            let _ = no_rollback_on_error;
            let _ = meta;
        }
        AlterInstanceAction::ReloadKeyring { meta } => {
            let _ = meta;
        }
        AlterInstanceAction::EnableInnodbRedoLog { meta } => {
            let _ = meta;
        }
        AlterInstanceAction::DisableInnodbRedoLog { meta } => {
            let _ = meta;
        }
    }
}
