///Walk the immediate children of a [`AlterTablespaceAction`] node.
pub fn walk_alter_tablespace_action<'ast, V, X>(visitor: &mut V, node: &'ast AlterTablespaceAction)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        AlterTablespaceAction::AddDatafile {
            datafile,
            options,
            meta,
        } => {
            visitor.visit_literal(datafile);
            for item in options.iter() {
                visitor.visit_tablespace_option(item);
            }
            let _ = meta;
        }
        AlterTablespaceAction::DropDatafile {
            datafile,
            options,
            meta,
        } => {
            visitor.visit_literal(datafile);
            for item in options.iter() {
                visitor.visit_tablespace_option(item);
            }
            let _ = meta;
        }
        AlterTablespaceAction::Rename { new_name, meta } => {
            visitor.visit_ident(new_name);
            let _ = meta;
        }
        AlterTablespaceAction::Options { options, meta } => {
            for item in options.iter() {
                visitor.visit_tablespace_option(item);
            }
            let _ = meta;
        }
        AlterTablespaceAction::SetState {
            state,
            options,
            meta,
        } => {
            visitor.visit_undo_tablespace_state(state);
            for item in options.iter() {
                visitor.visit_tablespace_option(item);
            }
            let _ = meta;
        }
    }
}
