///Walk the immediate children of a [`Insert`] node.
pub fn walk_insert<'ast, V, X>(visitor: &mut V, node: &'ast Insert<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Insert {
        verb,
        modifier,
        or_action,
        with,
        target,
        column_matching,
        overriding,
        source,
        row_alias,
        upsert,
        returning,
        meta,
    } = node;
    visitor.visit_insert_verb(verb);
    if let Some(item) = modifier.as_ref() {
        visitor.visit_insert_modifier(item);
    }
    if let Some(item) = or_action.as_ref() {
        visitor.visit_conflict_resolution(item);
    }
    if let Some(item) = with.as_ref() {
        visitor.visit_with(item);
    }
    visitor.visit_insert_target(target);
    if let Some(item) = column_matching.as_ref() {
        visitor.visit_insert_column_matching(item);
    }
    if let Some(item) = overriding.as_ref() {
        visitor.visit_insert_overriding(item);
    }
    visitor.visit_insert_source(source);
    if let Some(item) = row_alias.as_ref() {
        visitor.visit_table_alias(item);
    }
    if let Some(item) = upsert.as_ref() {
        visitor.visit_upsert(item);
    }
    if let Some(item) = returning.as_ref() {
        visitor.visit_returning(item);
    }
    let _ = meta;
}
