///Walk the immediate children of a [`Update`] node.
pub fn walk_update<'ast, V, X>(visitor: &mut V, node: &'ast Update<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Update {
        with,
        or_action,
        target,
        target_joins,
        assignments,
        from,
        selection,
        order_by,
        limit,
        returning,
        meta,
    } = node;
    if let Some(item) = with.as_ref() {
        visitor.visit_with(item);
    }
    if let Some(item) = or_action.as_ref() {
        visitor.visit_conflict_resolution(item);
    }
    visitor.visit_dml_target(target);
    for item in target_joins.iter() {
        visitor.visit_join(item);
    }
    for item in assignments.iter() {
        visitor.visit_update_assignment(item);
    }
    for item in from.iter() {
        visitor.visit_table_with_joins(item);
    }
    if let Some(item) = selection.as_ref() {
        visitor.visit_dml_selection(item);
    }
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    if let Some(item) = limit.as_ref() {
        visitor.visit_limit(item);
    }
    if let Some(item) = returning.as_ref() {
        visitor.visit_returning(item);
    }
    let _ = meta;
}
