///Walk the immediate children of a [`MergeAction`] node.
pub fn walk_merge_action<'ast, V, X>(visitor: &mut V, node: &'ast MergeAction<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        MergeAction::Insert {
            columns,
            overriding,
            values,
            additional_rows,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            if let Some(item) = overriding.as_ref() {
                visitor.visit_insert_overriding(item);
            }
            for item in values.iter() {
                visitor.visit_insert_value(item);
            }
            for item in additional_rows.iter() {
                for item1 in item.iter() {
                    visitor.visit_insert_value(item1);
                }
            }
            let _ = meta;
        }
        MergeAction::InsertDefault { default, meta } => {
            visitor.visit_default_value(default);
            let _ = meta;
        }
        MergeAction::Update { assignments, meta } => {
            for item in assignments.iter() {
                visitor.visit_update_assignment(item);
            }
            let _ = meta;
        }
        MergeAction::UpdateStar { meta } => {
            let _ = meta;
        }
        MergeAction::InsertStar { meta } => {
            let _ = meta;
        }
        MergeAction::InsertByName { star, meta } => {
            let _ = star;
            let _ = meta;
        }
        MergeAction::Error { meta } => {
            let _ = meta;
        }
        MergeAction::Delete { meta } => {
            let _ = meta;
        }
        MergeAction::DoNothing { meta } => {
            let _ = meta;
        }
    }
}
///Walk the immediate children of a [`Expr`] node.
pub fn walk_expr<'ast, V, X>(visitor: &mut V, node: &'ast Expr<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        Expr::Column { name, meta } => {
            visitor.visit_object_name(name);
            let _ = meta;
        }
        Expr::Literal { literal, meta } => {
            visitor.visit_literal(literal);
            let _ = meta;
        }
        Expr::BinaryOp {
            left,
            op,
            right,
            meta,
        } => {
            visitor.visit_expr(left);
            visitor.visit_binary_operator(op);
            visitor.visit_expr(right);
            let _ = meta;
        }
        Expr::UnaryOp { op, expr, meta } => {
            visitor.visit_unary_operator(op);
            visitor.visit_expr(expr);
            let _ = meta;
        }
        Expr::Function { call, meta } => {
            visitor.visit_function_call(call);
            let _ = meta;
        }
        Expr::Case { case, meta } => {
            visitor.visit_case_expr(case);
            let _ = meta;
        }
        Expr::Extract { extract, meta } => {
            visitor.visit_extract_expr(extract);
            let _ = meta;
        }
        Expr::Cast {
            expr,
            data_type,
            syntax,
            try_cast,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_data_type(data_type);
            visitor.visit_cast_syntax(syntax);
            let _ = try_cast;
            let _ = meta;
        }
        Expr::IsNull {
            expr,
            negated,
            spelling,
            meta,
        } => {
            visitor.visit_expr(expr);
            let _ = negated;
            visitor.visit_null_test_spelling(spelling);
            let _ = meta;
        }
        Expr::IsTruth {
            expr,
            value,
            negated,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_truth_value(value);
            let _ = negated;
            let _ = meta;
        }
        Expr::IsNormalized {
            expr,
            form,
            negated,
            meta,
        } => {
            visitor.visit_expr(expr);
            if let Some(item) = form.as_ref() {
                visitor.visit_normalization_form(item);
            }
            let _ = negated;
            let _ = meta;
        }
        Expr::Between {
            expr,
            low,
            high,
            negated,
            symmetric,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_expr(low);
            visitor.visit_expr(high);
            let _ = negated;
            let _ = symmetric;
            let _ = meta;
        }
        Expr::Like {
            expr,
            pattern,
            escape,
            negated,
            spelling,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_expr(pattern);
            if let Some(item) = escape.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = negated;
            visitor.visit_like_spelling(spelling);
            let _ = meta;
        }
        Expr::InList {
            expr,
            list,
            negated,
            meta,
        } => {
            visitor.visit_expr(expr);
            for item in list.iter() {
                visitor.visit_expr(item);
            }
            let _ = negated;
            let _ = meta;
        }
        Expr::InSubquery {
            expr,
            subquery,
            negated,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_query(subquery);
            let _ = negated;
            let _ = meta;
        }
        Expr::InExpr {
            expr,
            rhs,
            negated,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_expr(rhs);
            let _ = negated;
            let _ = meta;
        }
        Expr::Exists { query, meta } => {
            visitor.visit_query(query);
            let _ = meta;
        }
        Expr::QuantifiedComparison {
            left,
            op,
            quantifier,
            subquery,
            meta,
        } => {
            visitor.visit_expr(left);
            visitor.visit_binary_operator(op);
            visitor.visit_quantifier(quantifier);
            visitor.visit_query(subquery);
            let _ = meta;
        }
        Expr::QuantifiedList {
            left,
            op,
            quantifier,
            array,
            meta,
        } => {
            visitor.visit_expr(left);
            visitor.visit_binary_operator(op);
            visitor.visit_quantifier(quantifier);
            visitor.visit_expr(array);
            let _ = meta;
        }
        Expr::QuantifiedLike {
            left,
            pattern,
            quantifier,
            negated,
            spelling,
            meta,
        } => {
            visitor.visit_expr(left);
            visitor.visit_expr(pattern);
            visitor.visit_quantifier(quantifier);
            let _ = negated;
            visitor.visit_like_spelling(spelling);
            let _ = meta;
        }
        Expr::Subquery { query, meta } => {
            visitor.visit_query(query);
            let _ = meta;
        }
        Expr::Parameter { kind, meta } => {
            visitor.visit_parameter_kind(kind);
            let _ = meta;
        }
        Expr::PositionalColumn { index, meta } => {
            let _ = index;
            let _ = meta;
        }
        Expr::SessionVariable { kind, name, meta } => {
            visitor.visit_session_variable_kind(kind);
            let _ = name;
            let _ = meta;
        }
        Expr::Subscript { subscript, meta } => {
            visitor.visit_subscript_expr(subscript);
            let _ = meta;
        }
        Expr::SemiStructuredAccess {
            semi_structured_access,
            meta,
        } => {
            visitor.visit_semi_structured_access_expr(semi_structured_access);
            let _ = meta;
        }
        Expr::Collate { collate, meta } => {
            visitor.visit_collate_expr(collate);
            let _ = meta;
        }
        Expr::Interval { value, unit, meta } => {
            visitor.visit_expr(value);
            visitor.visit_interval_fields(unit);
            let _ = meta;
        }
        Expr::AtTimeZone { at_time_zone, meta } => {
            visitor.visit_at_time_zone_expr(at_time_zone);
            let _ = meta;
        }
        Expr::Array { array, meta } => {
            visitor.visit_array_expr(array);
            let _ = meta;
        }
        Expr::Struct { r#struct, meta } => {
            visitor.visit_struct_expr(r#struct);
            let _ = meta;
        }
        Expr::StructConstructor { constructor, meta } => {
            visitor.visit_struct_constructor_expr(constructor);
            let _ = meta;
        }
        Expr::Map { map, meta } => {
            visitor.visit_map_expr(map);
            let _ = meta;
        }
        Expr::Row { row, meta } => {
            visitor.visit_row_expr(row);
            let _ = meta;
        }
        Expr::FieldSelection {
            field_selection,
            meta,
        } => {
            visitor.visit_field_selection_expr(field_selection);
            let _ = meta;
        }
        Expr::NamedOperator {
            named_operator,
            meta,
        } => {
            visitor.visit_named_operator_expr(named_operator);
            let _ = meta;
        }
        Expr::PrefixOperator {
            prefix_operator,
            meta,
        } => {
            visitor.visit_prefix_operator_expr(prefix_operator);
            let _ = meta;
        }
        Expr::PostfixOperator {
            postfix_operator,
            meta,
        } => {
            visitor.visit_postfix_operator_expr(postfix_operator);
            let _ = meta;
        }
        Expr::Lambda { lambda, meta } => {
            visitor.visit_lambda_expr(lambda);
            let _ = meta;
        }
        Expr::Columns {
            qualifier,
            pattern,
            options,
            spelling,
            meta,
        } => {
            if let Some(item) = qualifier.as_ref() {
                visitor.visit_object_name(item);
            }
            if let Some(item) = pattern.as_ref() {
                visitor.visit_expr(item);
            }
            if let Some(item) = options.as_ref() {
                visitor.visit_wildcard_options(item);
            }
            visitor.visit_columns_spelling(spelling);
            let _ = meta;
        }
        Expr::SpecialFunction {
            keyword,
            precision,
            meta,
        } => {
            visitor.visit_special_function_keyword(keyword);
            let _ = precision;
            let _ = meta;
        }
        Expr::JsonFunc { json_func, meta } => {
            visitor.visit_json_func_expr(json_func);
            let _ = meta;
        }
        Expr::JsonObject { json_object, meta } => {
            visitor.visit_json_object_expr(json_object);
            let _ = meta;
        }
        Expr::JsonArray { json_array, meta } => {
            visitor.visit_json_array_expr(json_array);
            let _ = meta;
        }
        Expr::JsonAggregate {
            json_aggregate,
            meta,
        } => {
            visitor.visit_json_aggregate_expr(json_aggregate);
            let _ = meta;
        }
        Expr::JsonConstructor {
            json_constructor,
            meta,
        } => {
            visitor.visit_json_constructor_expr(json_constructor);
            let _ = meta;
        }
        Expr::IsJson { is_json, meta } => {
            visitor.visit_is_json_expr(is_json);
            let _ = meta;
        }
        Expr::XmlFunc { xml_func, meta } => {
            visitor.visit_xml_func(xml_func);
            let _ = meta;
        }
        Expr::IsDocument {
            expr,
            negated,
            meta,
        } => {
            visitor.visit_expr(expr);
            let _ = negated;
            let _ = meta;
        }
        Expr::StringFunc { string_func, meta } => {
            visitor.visit_string_func(string_func);
            let _ = meta;
        }
        Expr::Other { ext, meta } => {
            visitor.visit_extension(ext);
            let _ = meta;
        }
    }
}
