pub fn walk_subscript_expr<'ast, V, X>(visitor: &mut V, node: &'ast SubscriptExpr<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let SubscriptExpr {
        base,
        lower,
        upper,
        step,
        kind,
        meta,
    } = node;
    visitor.visit_expr(base);
    if let Some(item) = lower.as_ref() {
        visitor.visit_expr(item);
    }
    if let Some(item) = upper.as_ref() {
        visitor.visit_expr(item);
    }
    if let Some(item) = step.as_ref() {
        visitor.visit_expr(item);
    }
    visitor.visit_subscript_kind(kind);
    let _ = meta;
}
