///Walk the immediate children of a [`FunctionCall`] node.
pub fn walk_function_call<'ast, V, X>(visitor: &mut V, node: &'ast FunctionCall<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let FunctionCall {
        name,
        quantifier,
        args,
        wildcard,
        order_by,
        within_group,
        separator,
        filter,
        filter_where,
        over,
        null_treatment,
        window_tail,
        meta,
    } = node;
    visitor.visit_object_name(name);
    if let Some(item) = quantifier.as_ref() {
        visitor.visit_set_quantifier(item);
    }
    for item in args.iter() {
        visitor.visit_function_arg(item);
    }
    let _ = wildcard;
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    if let Some(item) = within_group.as_ref() {
        for item1 in item.iter() {
            visitor.visit_order_by_expr(item1);
        }
    }
    if let Some(item) = separator.as_ref() {
        visitor.visit_literal(item);
    }
    if let Some(item) = filter.as_ref() {
        visitor.visit_expr(item);
    }
    visitor.visit_filter_where_spelling(filter_where);
    if let Some(item) = over.as_ref() {
        visitor.visit_window_spec(item);
    }
    if let Some(item) = null_treatment.as_ref() {
        visitor.visit_null_treatment(item);
    }
    if let Some(item) = window_tail.as_ref() {
        visitor.visit_window_function_tail(item);
    }
    let _ = meta;
}
