    visitor.visit_json_wrapper_behavior(wrapper);
    visitor.visit_json_quotes_behavior(quotes);
    if let Some(item) = on_empty.as_ref() {
        visitor.visit_json_behavior(item);
    }
    if let Some(item) = on_error.as_ref() {
        visitor.visit_json_behavior(item);
    }
    let _ = meta;
