///Walk the immediate children of a [`XmlFunc`] node.
pub fn walk_xml_func<'ast, V, X>(visitor: &mut V, node: &'ast XmlFunc<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        XmlFunc::Element {
            name,
            attributes,
            content,
            meta,
        } => {
            visitor.visit_ident(name);
            for item in attributes.iter() {
                visitor.visit_xml_attribute(item);
            }
            for item in content.iter() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        XmlFunc::Forest { elements, meta } => {
            for item in elements.iter() {
                visitor.visit_xml_attribute(item);
            }
            let _ = meta;
        }
        XmlFunc::Concat { args, meta } => {
            for item in args.iter() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        XmlFunc::Parse {
            option,
            arg,
            whitespace,
            meta,
        } => {
            visitor.visit_xml_document_or_content(option);
            visitor.visit_expr(arg);
            visitor.visit_xml_whitespace_option(whitespace);
            let _ = meta;
        }
        XmlFunc::Pi {
            name,
            content,
            meta,
        } => {
            visitor.visit_ident(name);
            if let Some(item) = content.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        XmlFunc::Root {
            arg,
            version,
            standalone,
            meta,
        } => {
            visitor.visit_expr(arg);
            if let Some(item) = version.as_ref() {
                visitor.visit_expr(item);
            }
            visitor.visit_xml_standalone(standalone);
            let _ = meta;
        }
        XmlFunc::Serialize {
            option,
            arg,
            data_type,
            indent,
            meta,
        } => {
            visitor.visit_xml_document_or_content(option);
            visitor.visit_expr(arg);
            visitor.visit_data_type(data_type);
            visitor.visit_xml_indent_option(indent);
            let _ = meta;
        }
        XmlFunc::Exists {
            path,
            mechanism_before,
            arg,
            mechanism_after,
            meta,
        } => {
            visitor.visit_expr(path);
            if let Some(item) = mechanism_before.as_ref() {
                visitor.visit_xml_passing_mechanism(item);
            }
            visitor.visit_expr(arg);
            if let Some(item) = mechanism_after.as_ref() {
                visitor.visit_xml_passing_mechanism(item);
            }
            let _ = meta;
        }
    }
}
