///Walk the immediate children of a [`StringFunc`] node.
pub fn walk_string_func<'ast, V, X>(visitor: &mut V, node: &'ast StringFunc<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        StringFunc::Substring {
            expr,
            start,
            count,
            meta,
        } => {
            visitor.visit_expr(expr);
            if let Some(item) = start.as_ref() {
                visitor.visit_expr(item);
            }
            if let Some(item) = count.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        StringFunc::SubstringSimilar {
            expr,
            pattern,
            escape,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_expr(pattern);
            visitor.visit_expr(escape);
            let _ = meta;
        }
        StringFunc::Position {
            substr,
            string,
            meta,
        } => {
            visitor.visit_expr(substr);
            visitor.visit_expr(string);
            let _ = meta;
        }
        StringFunc::Overlay {
            target,
            replacement,
            start,
            count,
            meta,
        } => {
            visitor.visit_expr(target);
            visitor.visit_expr(replacement);
            visitor.visit_expr(start);
            if let Some(item) = count.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        StringFunc::Trim {
            side,
            trim_chars,
            from,
            sources,
            meta,
        } => {
            if let Some(item) = side.as_ref() {
                visitor.visit_trim_side(item);
            }
            if let Some(item) = trim_chars.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = from;
            for item in sources.iter() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        StringFunc::CollationFor { expr, meta } => {
            visitor.visit_expr(expr);
            let _ = meta;
        }
        StringFunc::ConvertUsing {
            expr,
            charset,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_ident(charset);
            let _ = meta;
        }
        StringFunc::MatchAgainst {
            columns,
            against,
            modifier,
            meta,
        } => {
            for item in columns.iter() {
                visitor.visit_expr(item);
            }
            visitor.visit_expr(against);
            if let Some(item) = modifier.as_ref() {
                visitor.visit_match_search_modifier(item);
            }
            let _ = meta;
        }
        StringFunc::CeilTo {
            expr,
            field,
            spelling,
            meta,
        } => {
            visitor.visit_expr(expr);
            visitor.visit_ident(field);
            visitor.visit_ceil_spelling(spelling);
            let _ = meta;
        }
        StringFunc::FloorTo { expr, field, meta } => {
            visitor.visit_expr(expr);
            visitor.visit_ident(field);
            let _ = meta;
        }
    }
}
