///Walk the immediate children of a [`BinaryOperator`] node.
pub fn walk_binary_operator<'ast, V, X>(visitor: &mut V, node: &'ast BinaryOperator)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        BinaryOperator::Plus => {}
        BinaryOperator::Minus => {}
        BinaryOperator::Multiply => {}
        BinaryOperator::Divide => {}
        BinaryOperator::Modulo(field0) => {
            visitor.visit_modulo_spelling(field0);
        }
        BinaryOperator::IntegerDivide(field0) => {
            visitor.visit_integer_divide_spelling(field0);
        }
        BinaryOperator::Exponent => {}
        BinaryOperator::StringConcat => {}
        BinaryOperator::Contains => {}
        BinaryOperator::ContainedBy => {}
        BinaryOperator::StartsWith => {}
        BinaryOperator::Overlap => {}
        BinaryOperator::JsonGet => {}
        BinaryOperator::JsonGetText => {}
        BinaryOperator::JsonExists => {}
        BinaryOperator::JsonExistsAny => {}
        BinaryOperator::JsonExistsAll => {}
        BinaryOperator::JsonPathExists => {}
        BinaryOperator::JsonPathMatch => {}
        BinaryOperator::JsonExtractPath => {}
        BinaryOperator::JsonExtractPathText => {}
        BinaryOperator::JsonDeletePath => {}
        BinaryOperator::BitwiseOr => {}
        BinaryOperator::BitwiseAnd => {}
        BinaryOperator::BitwiseShiftLeft => {}
        BinaryOperator::BitwiseShiftRight => {}
        BinaryOperator::BitwiseXor(field0) => {
            visitor.visit_bitwise_xor_spelling(field0);
        }
        BinaryOperator::Eq(field0) => {
            visitor.visit_equals_spelling(field0);
        }
        BinaryOperator::NotEq(field0) => {
            visitor.visit_not_eq_spelling(field0);
        }
        BinaryOperator::Lt => {}
        BinaryOperator::LtEq => {}
        BinaryOperator::Gt => {}
        BinaryOperator::GtEq => {}
        BinaryOperator::IsDistinctFrom(field0) => {
            visitor.visit_is_distinct_from_spelling(field0);
        }
        BinaryOperator::IsNotDistinctFrom(field0) => {
            visitor.visit_is_not_distinct_from_spelling(field0);
        }
        BinaryOperator::Regexp(field0) => {
            visitor.visit_regexp_spelling(field0);
        }
        BinaryOperator::Glob => {}
        BinaryOperator::Match => {}
        BinaryOperator::Overlaps => {}
        BinaryOperator::And => {}
        BinaryOperator::Xor => {}
        BinaryOperator::Or => {}
    }
}
