///Walk the immediate children of a [`MatchRecognize`] node.
pub fn walk_match_recognize<'ast, V, X>(visitor: &mut V, node: &'ast MatchRecognize<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let MatchRecognize {
        source,
        partition_by,
        order_by,
        measures,
        rows_per_match,
        after_match_skip,
        pattern,
        subsets,
        define,
        meta,
    } = node;
    visitor.visit_table_factor(source);
    for item in partition_by.iter() {
        visitor.visit_expr(item);
    }
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    for item in measures.iter() {
        visitor.visit_measure(item);
    }
    if let Some(item) = rows_per_match.as_ref() {
        visitor.visit_rows_per_match(item);
    }
    if let Some(item) = after_match_skip.as_ref() {
        visitor.visit_after_match_skip(item);
    }
    visitor.visit_match_recognize_pattern(pattern);
    for item in subsets.iter() {
        visitor.visit_subset_definition(item);
    }
    for item in define.iter() {
        visitor.visit_symbol_definition(item);
    }
    let _ = meta;
}
