///Walk the immediate children of a [`MatchRecognizePattern`] node.
pub fn walk_match_recognize_pattern<'ast, V, X>(visitor: &mut V, node: &'ast MatchRecognizePattern)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        MatchRecognizePattern::Symbol { symbol, meta } => {
            visitor.visit_ident(symbol);
            let _ = meta;
        }
        MatchRecognizePattern::Start { meta } => {
            let _ = meta;
        }
        MatchRecognizePattern::End { meta } => {
            let _ = meta;
        }
        MatchRecognizePattern::Concat { patterns, meta } => {
            for item in patterns.iter() {
                visitor.visit_match_recognize_pattern(item);
            }
            let _ = meta;
        }
        MatchRecognizePattern::Alternation { patterns, meta } => {
            for item in patterns.iter() {
                visitor.visit_match_recognize_pattern(item);
            }
            let _ = meta;
        }
        MatchRecognizePattern::Group { pattern, meta } => {
            visitor.visit_match_recognize_pattern(pattern);
            let _ = meta;
        }
        MatchRecognizePattern::Exclude { pattern, meta } => {
            visitor.visit_match_recognize_pattern(pattern);
            let _ = meta;
        }
        MatchRecognizePattern::Permute { patterns, meta } => {
            for item in patterns.iter() {
                visitor.visit_match_recognize_pattern(item);
            }
            let _ = meta;
        }
        MatchRecognizePattern::Repetition {
            pattern,
            quantifier,
            meta,
        } => {
            visitor.visit_match_recognize_pattern(pattern);
            visitor.visit_repetition_quantifier(quantifier);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a [`RepetitionQuantifier`] node.
pub fn walk_repetition_quantifier<'ast, V, X>(visitor: &mut V, node: &'ast RepetitionQuantifier)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        RepetitionQuantifier::ZeroOrMore => {}
        RepetitionQuantifier::OneOrMore => {}
        RepetitionQuantifier::AtMostOne => {}
        RepetitionQuantifier::Exactly(field0) => {
            let _ = field0;
        }
        RepetitionQuantifier::AtLeast(field0) => {
            let _ = field0;
        }
        RepetitionQuantifier::AtMost(field0) => {
            let _ = field0;
        }
        RepetitionQuantifier::Range(field0, field1) => {
            let _ = field0;
            let _ = field1;
        }
    }
}
///Walk the immediate children of a [`PipeOperator`] node.
pub fn walk_pipe_operator<'ast, V, X>(visitor: &mut V, node: &'ast PipeOperator<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        PipeOperator::Where { predicate, meta } => {
            visitor.visit_expr(predicate);
            let _ = meta;
        }
        PipeOperator::Select { items, meta } => {
            for item in items.iter() {
                visitor.visit_select_item(item);
            }
            let _ = meta;
        }
        PipeOperator::Extend { items, meta } => {
            for item in items.iter() {
                visitor.visit_select_item(item);
            }
            let _ = meta;
        }
        PipeOperator::As { alias, meta } => {
            visitor.visit_table_alias(alias);
            let _ = meta;
        }
        PipeOperator::OrderBy { keys, meta } => {
            for item in keys.iter() {
                visitor.visit_order_by_expr(item);
            }
            let _ = meta;
        }
        PipeOperator::Limit {
            count,
            offset,
            meta,
        } => {
            visitor.visit_expr(count);
            if let Some(item) = offset.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        PipeOperator::Join { join, meta } => {
            visitor.visit_join(join);
            let _ = meta;
        }
        PipeOperator::SetOperation {
            op,
            quantifier,
            queries,
            meta,
        } => {
            visitor.visit_set_operator(op);
            if let Some(item) = quantifier.as_ref() {
                visitor.visit_set_quantifier(item);
            }
            for item in queries.iter() {
                visitor.visit_query(item);
            }
            let _ = meta;
        }
        PipeOperator::Set { assignments, meta } => {
            for item in assignments.iter() {
                visitor.visit_update_assignment(item);
            }
            let _ = meta;
        }
        PipeOperator::Call { call, alias, meta } => {
            visitor.visit_function_call(call);
            if let Some(item) = alias.as_ref() {
                visitor.visit_table_alias(item);
            }
            let _ = meta;
        }
        PipeOperator::Aggregate {
            aggregates,
            group_by,
            meta,
        } => {
            for item in aggregates.iter() {
                visitor.visit_pipe_aggregate_expr(item);
            }
            for item in group_by.iter() {
                visitor.visit_pipe_aggregate_expr(item);
            }
            let _ = meta;
        }
        PipeOperator::Drop { columns, meta } => {
            for item in columns.iter() {
                visitor.visit_ident(item);
            }
            let _ = meta;
        }
        PipeOperator::Rename { renames, meta } => {
            for item in renames.iter() {
                visitor.visit_pipe_rename_item(item);
            }
            let _ = meta;
        }
        PipeOperator::Pivot {
            aggregates,
            column,
            meta,
        } => {
            for item in aggregates.iter() {
                visitor.visit_pivot_expr(item);
            }
            visitor.visit_pivot_column(column);
            let _ = meta;
        }
        PipeOperator::Unpivot {
            value,
            name,
            columns,
            meta,
        } => {
            for item in value.iter() {
                visitor.visit_ident(item);
            }
            for item in name.iter() {
                visitor.visit_ident(item);
            }
            for item in columns.iter() {
                visitor.visit_unpivot_column(item);
            }
            let _ = meta;
        }
        PipeOperator::TableSample { sample, meta } => {
            visitor.visit_table_sample(sample);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a [`PipeAggregateExpr`] node.
pub fn walk_pipe_aggregate_expr<'ast, V, X>(visitor: &mut V, node: &'ast PipeAggregateExpr<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let PipeAggregateExpr {
        expr,
        alias,
        asc,
        nulls_first,
        meta,
    } = node;
    visitor.visit_expr(expr);
    if let Some(item) = alias.as_ref() {
        visitor.visit_ident(item);
    }
    let _ = asc;
    let _ = nulls_first;
    let _ = meta;
}
///Walk the immediate children of a [`PipeRenameItem`] node.
pub fn walk_pipe_rename_item<'ast, V, X>(visitor: &mut V, node: &'ast PipeRenameItem)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let PipeRenameItem { old, new, meta } = node;
    visitor.visit_ident(old);
    visitor.visit_ident(new);
    let _ = meta;
}
///Walk the immediate children of a [`Pivot`] node.
pub fn walk_pivot<'ast, V, X>(visitor: &mut V, node: &'ast Pivot<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Pivot {
        source,
        aggregates,
        pivot_on,
        group_by,
        with,
        order_by,
        order_by_all,
        limit,
        default_on_null,
        spelling,
        meta,
    } = node;
    visitor.visit_table_factor(source);
    for item in aggregates.iter() {
        visitor.visit_pivot_expr(item);
    }
    for item in pivot_on.iter() {
        visitor.visit_pivot_column(item);
    }
    for item in group_by.iter() {
        visitor.visit_expr(item);
    }
    if let Some(item) = with.as_ref() {
        visitor.visit_with(item);
    }
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    if let Some(item) = order_by_all.as_ref() {
        visitor.visit_order_by_all(item);
    }
    if let Some(item) = limit.as_ref() {
        visitor.visit_limit(item);
    }
    if let Some(item) = default_on_null.as_ref() {
        visitor.visit_expr(item);
    }
    visitor.visit_pivot_spelling(spelling);
    let _ = meta;
}
///Walk the immediate children of a [`Unpivot`] node.
pub fn walk_unpivot<'ast, V, X>(visitor: &mut V, node: &'ast Unpivot<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Unpivot {
        source,
        value,
        name,
        columns,
        null_inclusion,
        with,
        order_by,
        order_by_all,
        limit,
        spelling,
        meta,
    } = node;
    visitor.visit_table_factor(source);
    for item in value.iter() {
        visitor.visit_ident(item);
    }
    for item in name.iter() {
        visitor.visit_ident(item);
    }
    for item in columns.iter() {
        visitor.visit_unpivot_column(item);
    }
    if let Some(item) = null_inclusion.as_ref() {
        visitor.visit_null_inclusion(item);
    }
    if let Some(item) = with.as_ref() {
        visitor.visit_with(item);
    }
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    if let Some(item) = order_by_all.as_ref() {
        visitor.visit_order_by_all(item);
    }
    if let Some(item) = limit.as_ref() {
        visitor.visit_limit(item);
    }
    visitor.visit_unpivot_spelling(spelling);
    let _ = meta;
}
