///Walk the immediate children of a [`Query`] node.
pub fn walk_query<'ast, V, X>(visitor: &mut V, node: &'ast Query<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Query {
        with,
        body,
        order_by,
        order_by_all,
        limit_by,
        limit,
        settings,
        format,
        locking,
        pipe_operators,
        for_clause,
        meta,
    } = node;
    if let Some(item) = with.as_ref() {
        visitor.visit_with(item);
    }
    visitor.visit_set_expr(body);
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    if let Some(item) = order_by_all.as_ref() {
        visitor.visit_order_by_all(item);
    }
    if let Some(item) = limit_by.as_ref() {
        visitor.visit_limit_by(item);
    }
    if let Some(item) = limit.as_ref() {
        visitor.visit_limit(item);
    }
    for item in settings.iter() {
        visitor.visit_setting(item);
    }
    if let Some(item) = format.as_ref() {
        visitor.visit_format_clause(item);
    }
    for item in locking.iter() {
        visitor.visit_locking_clause(item);
    }
    for item in pipe_operators.iter() {
        visitor.visit_pipe_operator(item);
    }
    if let Some(item) = for_clause.as_ref() {
        visitor.visit_for_clause(item);
    }
    let _ = meta;
}
