///Walk the immediate children of a [`SetExpr`] node.
pub fn walk_set_expr<'ast, V, X>(visitor: &mut V, node: &'ast SetExpr<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SetExpr::Select { select, meta } => {
            visitor.visit_select(select);
            let _ = meta;
        }
        SetExpr::Values { values, meta } => {
            visitor.visit_values(values);
            let _ = meta;
        }
        SetExpr::Query { query, meta } => {
            visitor.visit_query(query);
            let _ = meta;
        }
        SetExpr::SetOperation {
            op,
            all,
            by_name,
            left,
            right,
            meta,
        } => {
            visitor.visit_set_operator(op);
            let _ = all;
            let _ = by_name;
            visitor.visit_set_expr(left);
            visitor.visit_set_expr(right);
            let _ = meta;
        }
        SetExpr::Pivot { pivot, meta } => {
            visitor.visit_pivot(pivot);
            let _ = meta;
        }
        SetExpr::Unpivot { unpivot, meta } => {
            visitor.visit_unpivot(unpivot);
            let _ = meta;
        }
    }
}
