///Walk the immediate children of a [`Select`] node.
pub fn walk_select<'ast, V, X>(visitor: &mut V, node: &'ast Select<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Select {
        distinct,
        straight_join,
        projection,
        into,
        from,
        lateral_views,
        selection,
        connect_by,
        group_by,
        group_by_quantifier,
        group_by_all,
        having,
        windows,
        qualify,
        sample,
        spelling,
        meta,
    } = node;
    if let Some(item) = distinct.as_ref() {
        visitor.visit_select_distinct(item);
    }
    let _ = straight_join;
    for item in projection.iter() {
        visitor.visit_select_item(item);
    }
    if let Some(item) = into.as_ref() {
        visitor.visit_into_target(item);
    }
    for item in from.iter() {
        visitor.visit_table_with_joins(item);
    }
    for item in lateral_views.iter() {
        visitor.visit_lateral_view(item);
    }
    if let Some(item) = selection.as_ref() {
        visitor.visit_expr(item);
    }
    if let Some(item) = connect_by.as_ref() {
        visitor.visit_hierarchical_clause(item);
    }
    for item in group_by.iter() {
        visitor.visit_group_by_item(item);
    }
    if let Some(item) = group_by_quantifier.as_ref() {
        visitor.visit_set_quantifier(item);
    }
    if let Some(item) = group_by_all.as_ref() {
        visitor.visit_group_by_all_spelling(item);
    }
    if let Some(item) = having.as_ref() {
        visitor.visit_expr(item);
    }
    for item in windows.iter() {
        visitor.visit_named_window(item);
    }
    if let Some(item) = qualify.as_ref() {
        visitor.visit_expr(item);
    }
    if let Some(item) = sample.as_ref() {
        visitor.visit_sample_clause(item);
    }
    visitor.visit_select_spelling(spelling);
    let _ = meta;
}
