///Walk the immediate children of a [`SelectItem`] node.
pub fn walk_select_item<'ast, V, X>(visitor: &mut V, node: &'ast SelectItem<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SelectItem::Wildcard {
            options,
            alias,
            alias_spelling,
            meta,
        } => {
            if let Some(item) = options.as_ref() {
                visitor.visit_wildcard_options(item);
            }
            if let Some(item) = alias.as_ref() {
                visitor.visit_ident(item);
            }
            visitor.visit_alias_spelling(alias_spelling);
            let _ = meta;
        }
        SelectItem::QualifiedWildcard {
            name,
            options,
            alias,
            alias_spelling,
            meta,
        } => {
            visitor.visit_object_name(name);
            if let Some(item) = options.as_ref() {
                visitor.visit_wildcard_options(item);
            }
            if let Some(item) = alias.as_ref() {
                visitor.visit_ident(item);
            }
            visitor.visit_alias_spelling(alias_spelling);
            let _ = meta;
        }
        SelectItem::Expr {
            expr,
            alias,
            alias_spelling,
            meta,
        } => {
            visitor.visit_expr(expr);
            if let Some(item) = alias.as_ref() {
                visitor.visit_ident(item);
            }
            visitor.visit_alias_spelling(alias_spelling);
            let _ = meta;
        }
    }
}
