///Walk the immediate children of a [`JoinOperator`] node.
pub fn walk_join_operator<'ast, V, X>(visitor: &mut V, node: &'ast JoinOperator<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        JoinOperator::Inner {
            straight,
            inner,
            constraint,
            meta,
        } => {
            let _ = straight;
            let _ = inner;
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::LeftOuter {
            outer,
            constraint,
            meta,
        } => {
            let _ = outer;
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::RightOuter {
            outer,
            constraint,
            meta,
        } => {
            let _ = outer;
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::FullOuter {
            outer,
            constraint,
            meta,
        } => {
            let _ = outer;
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::AsOf {
            kind,
            constraint,
            meta,
        } => {
            visitor.visit_as_of_join_kind(kind);
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::Cross { meta } => {
            let _ = meta;
        }
        JoinOperator::Positional { meta } => {
            let _ = meta;
        }
        JoinOperator::Semi {
            asof,
            side,
            constraint,
            meta,
        } => {
            let _ = asof;
            visitor.visit_semi_anti_side(side);
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::Anti {
            asof,
            side,
            constraint,
            meta,
        } => {
            let _ = asof;
            visitor.visit_semi_anti_side(side);
            visitor.visit_join_constraint(constraint);
            let _ = meta;
        }
        JoinOperator::Apply { kind, meta } => {
            visitor.visit_apply_kind(kind);
            let _ = meta;
        }
    }
}
