///Walk the immediate children of a [`HierarchicalClause`] node.
pub fn walk_hierarchical_clause<'ast, V, X>(visitor: &mut V, node: &'ast HierarchicalClause<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let HierarchicalClause {
        start_with,
        nocycle,
        connect_by,
        start_with_leads,
        meta,
    } = node;
    if let Some(item) = start_with.as_ref() {
        visitor.visit_expr(item);
    }
    let _ = nocycle;
    visitor.visit_expr(connect_by);
    let _ = start_with_leads;
    let _ = meta;
}
///Walk the immediate children of a [`ReplicationStatement`] node.
pub fn walk_replication_statement<'ast, V, X>(visitor: &mut V, node: &'ast ReplicationStatement)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ReplicationStatement::ChangeSource {
            options,
            channel,
            meta,
        } => {
            for item in options.iter() {
                visitor.visit_change_replication_source_option(item);
            }
            if let Some(item) = channel.as_ref() {
                visitor.visit_literal(item);
            }
            let _ = meta;
        }
        ReplicationStatement::ChangeFilter {
            rules,
            channel,
            meta,
        } => {
            for item in rules.iter() {
                visitor.visit_replication_filter_rule(item);
            }
            if let Some(item) = channel.as_ref() {
                visitor.visit_literal(item);
            }
            let _ = meta;
        }
        ReplicationStatement::StartReplica {
            threads,
            until,
            user,
            password,
            default_auth,
            plugin_dir,
            channel,
            meta,
        } => {
            for item in threads.iter() {
                visitor.visit_replica_thread_option(item);
            }
            for item in until.iter() {
                visitor.visit_replica_until_condition(item);
            }
            if let Some(item) = user.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = password.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = default_auth.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = plugin_dir.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = channel.as_ref() {
                visitor.visit_literal(item);
            }
            let _ = meta;
        }
        ReplicationStatement::StopReplica {
            threads,
            channel,
            meta,
        } => {
            for item in threads.iter() {
                visitor.visit_replica_thread_option(item);
            }
            if let Some(item) = channel.as_ref() {
                visitor.visit_literal(item);
            }
            let _ = meta;
        }
        ReplicationStatement::StartGroupReplication { options, meta } => {
            for item in options.iter() {
                visitor.visit_group_replication_option(item);
            }
            let _ = meta;
        }
        ReplicationStatement::StopGroupReplication { meta } => {
            let _ = meta;
        }
    }
}
