///Walk the immediate children of a [`CompoundStatement`] node.
pub fn walk_compound_statement<'ast, V, X>(visitor: &mut V, node: &'ast CompoundStatement<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let CompoundStatement {
        label,
        declarations,
        body,
        end_label,
        meta,
    } = node;
    if let Some(item) = label.as_ref() {
        visitor.visit_ident(item);
    }
    for item in declarations.iter() {
        visitor.visit_declaration(item);
    }
    for item in body.iter() {
        visitor.visit_statement(item);
    }
    if let Some(item) = end_label.as_ref() {
        visitor.visit_ident(item);
    }
    let _ = meta;
}
///Walk the immediate children of a [`Declaration`] node.
pub fn walk_declaration<'ast, V, X>(visitor: &mut V, node: &'ast Declaration<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        Declaration::Variable {
            names,
            data_type,
            default,
            meta,
        } => {
            for item in names.iter() {
                visitor.visit_ident(item);
            }
            visitor.visit_data_type(data_type);
            if let Some(item) = default.as_ref() {
                visitor.visit_expr(item);
            }
            let _ = meta;
        }
        Declaration::Condition { name, value, meta } => {
            visitor.visit_ident(name);
            visitor.visit_condition_value(value);
            let _ = meta;
        }
        Declaration::Cursor { name, query, meta } => {
            visitor.visit_ident(name);
            visitor.visit_query(query);
            let _ = meta;
        }
        Declaration::Handler {
            action,
            conditions,
            body,
            meta,
        } => {
            visitor.visit_handler_action(action);
            for item in conditions.iter() {
                visitor.visit_handler_condition(item);
            }
            visitor.visit_statement(body);
            let _ = meta;
        }
    }
}
