///Walk the immediate children of a [`IfStatement`] node.
pub fn walk_if_statement<'ast, V, X>(visitor: &mut V, node: &'ast IfStatement<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let IfStatement {
        branches,
        else_body,
        meta,
    } = node;
    for item in branches.iter() {
        visitor.visit_conditional_branch(item);
    }
    if let Some(item) = else_body.as_ref() {
        for item1 in item.iter() {
            visitor.visit_statement(item1);
        }
    }
    let _ = meta;
}
