///Walk the immediate children of a [`TransactionStatement`] node.
pub fn walk_transaction_statement<'ast, V, X>(visitor: &mut V, node: &'ast TransactionStatement)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TransactionStatement::Begin {
            syntax,
            mode,
            block,
            name,
            modes,
            meta,
        } => {
            visitor.visit_transaction_start(syntax);
            if let Some(item) = mode.as_ref() {
                visitor.visit_transaction_mode_kind(item);
            }
            if let Some(item) = block.as_ref() {
                visitor.visit_transaction_block_keyword(item);
            }
            if let Some(item) = name.as_ref() {
                visitor.visit_ident(item);
            }
            for item in modes.iter() {
                visitor.visit_transaction_mode(item);
            }
            let _ = meta;
        }
        TransactionStatement::Commit {
            syntax,
            block,
            name,
            chain,
            release,
            meta,
        } => {
            visitor.visit_transaction_commit_keyword(syntax);
            if let Some(item) = block.as_ref() {
                visitor.visit_transaction_block_keyword(item);
            }
            if let Some(item) = name.as_ref() {
                visitor.visit_ident(item);
            }
            let _ = chain;
            let _ = release;
            let _ = meta;
        }
        TransactionStatement::Rollback {
            syntax,
            block,
            name,
            savepoint_keyword,
            to_savepoint,
            chain,
            release,
            meta,
        } => {
            visitor.visit_transaction_rollback_keyword(syntax);
            if let Some(item) = block.as_ref() {
                visitor.visit_transaction_block_keyword(item);
            }
            if let Some(item) = name.as_ref() {
                visitor.visit_ident(item);
            }
            let _ = savepoint_keyword;
            if let Some(item) = to_savepoint.as_ref() {
                visitor.visit_ident(item);
            }
            let _ = chain;
            let _ = release;
            let _ = meta;
        }
        TransactionStatement::Savepoint { name, meta } => {
            visitor.visit_ident(name);
            let _ = meta;
        }
        TransactionStatement::Release {
            savepoint_keyword,
            savepoint,
            meta,
        } => {
            let _ = savepoint_keyword;
            visitor.visit_ident(savepoint);
            let _ = meta;
        }
        TransactionStatement::SetCharacteristics { modes, meta } => {
            for item in modes.iter() {
                visitor.visit_transaction_mode(item);
            }
            let _ = meta;
        }
    }
}
