///Walk the immediate children of a [`XaStatement`] node.
pub fn walk_xa_statement<'ast, V, X>(visitor: &mut V, node: &'ast XaStatement)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        XaStatement::Start {
            keyword,
            xid,
            association,
            meta,
        } => {
            visitor.visit_xa_start_keyword(keyword);
            visitor.visit_xid(xid);
            if let Some(item) = association.as_ref() {
                visitor.visit_xa_association(item);
            }
            let _ = meta;
        }
        XaStatement::End { xid, suspend, meta } => {
            visitor.visit_xid(xid);
            if let Some(item) = suspend.as_ref() {
                visitor.visit_xa_suspend(item);
            }
            let _ = meta;
        }
        XaStatement::Prepare { xid, meta } => {
            visitor.visit_xid(xid);
            let _ = meta;
        }
        XaStatement::Commit {
            xid,
            one_phase,
            meta,
        } => {
            visitor.visit_xid(xid);
            let _ = one_phase;
            let _ = meta;
        }
        XaStatement::Rollback { xid, meta } => {
            visitor.visit_xid(xid);
            let _ = meta;
        }
        XaStatement::Recover { convert_xid, meta } => {
            let _ = convert_xid;
            let _ = meta;
        }
    }
}
