///Walk the immediate children of a [`CopyStatement`] node.
pub fn walk_copy_statement<'ast, V, X>(visitor: &mut V, node: &'ast CopyStatement<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let CopyStatement {
        binary,
        source,
        direction,
        target,
        delimiters,
        parenthesized,
        options,
        filter,
        meta,
    } = node;
    let _ = binary;
    visitor.visit_copy_source(source);
    visitor.visit_copy_direction(direction);
    visitor.visit_copy_target(target);
    if let Some(item) = delimiters.as_ref() {
        visitor.visit_literal(item);
    }
    let _ = parenthesized;
    for item in options.iter() {
        visitor.visit_copy_option(item);
    }
    if let Some(item) = filter.as_ref() {
        visitor.visit_expr(item);
    }
    let _ = meta;
}
