///Walk the immediate children of a [`TableMaintenanceKind`] node.
pub fn walk_table_maintenance_kind<'ast, V, X>(visitor: &mut V, node: &'ast TableMaintenanceKind)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TableMaintenanceKind::Analyze {
            no_write_to_binlog,
            histogram,
            meta,
        } => {
            if let Some(item) = no_write_to_binlog.as_ref() {
                visitor.visit_no_write_to_binlog(item);
            }
            if let Some(item) = histogram.as_ref() {
                visitor.visit_analyze_histogram(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Check { options, meta } => {
            for item in options.iter() {
                visitor.visit_check_table_option(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Checksum { option, meta } => {
            if let Some(item) = option.as_ref() {
                visitor.visit_checksum_table_option(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Optimize {
            no_write_to_binlog,
            meta,
        } => {
            if let Some(item) = no_write_to_binlog.as_ref() {
                visitor.visit_no_write_to_binlog(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Repair {
            no_write_to_binlog,
            options,
            meta,
        } => {
            if let Some(item) = no_write_to_binlog.as_ref() {
                visitor.visit_no_write_to_binlog(item);
            }
            for item in options.iter() {
                visitor.visit_repair_table_option(item);
            }
            let _ = meta;
        }
    }
}
