///Walk the immediate children of a [`LoadDataStatement`] node.
pub fn walk_load_data_statement<'ast, V, X>(visitor: &mut V, node: &'ast LoadDataStatement<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let LoadDataStatement {
        format,
        concurrency,
        local,
        file,
        on_duplicate,
        table,
        partitions,
        charset,
        rows_identified_by,
        fields,
        lines,
        ignore_rows,
        columns,
        set,
        meta,
    } = node;
    visitor.visit_load_data_format(format);
    if let Some(item) = concurrency.as_ref() {
        visitor.visit_load_data_concurrency(item);
    }
    let _ = local;
    visitor.visit_literal(file);
    if let Some(item) = on_duplicate.as_ref() {
        visitor.visit_load_data_duplicate(item);
    }
    visitor.visit_object_name(table);
    for item in partitions.iter() {
        visitor.visit_ident(item);
    }
    if let Some(item) = charset.as_ref() {
        visitor.visit_ident(item);
    }
    if let Some(item) = rows_identified_by.as_ref() {
        visitor.visit_literal(item);
    }
    if let Some(item) = fields.as_ref() {
        visitor.visit_load_data_fields(item);
    }
    if let Some(item) = lines.as_ref() {
        visitor.visit_load_data_lines(item);
    }
    if let Some(item) = ignore_rows.as_ref() {
        visitor.visit_load_data_ignore_rows(item);
    }
    for item in columns.iter() {
        visitor.visit_load_data_field_or_var(item);
    }
    for item in set.iter() {
        visitor.visit_update_assignment(item);
    }
    let _ = meta;
}
