///Walk the immediate children of a [`ShowTarget`] node.
pub fn walk_show_target<'ast, V, X>(visitor: &mut V, node: &'ast ShowTarget<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ShowTarget::Tables {
            extended,
            full,
            all,
            from,
            filter,
            meta,
        } => {
            let _ = extended;
            let _ = full;
            let _ = all;
            if let Some(item) = from.as_ref() {
                visitor.visit_show_from(item);
            }
            if let Some(item) = filter.as_ref() {
                visitor.visit_show_filter(item);
            }
            let _ = meta;
        }
        ShowTarget::Columns {
            extended,
            full,
            spelling,
            table,
            database,
            filter,
            meta,
        } => {
            let _ = extended;
            let _ = full;
            visitor.visit_show_columns_spelling(spelling);
            visitor.visit_show_from(table);
            if let Some(item) = database.as_ref() {
                visitor.visit_show_from(item);
            }
            if let Some(item) = filter.as_ref() {
                visitor.visit_show_filter(item);
            }
            let _ = meta;
        }
        ShowTarget::Create {
            kind,
            name,
            if_not_exists,
            meta,
        } => {
            visitor.visit_show_create_kind(kind);
            visitor.visit_object_name(name);
            let _ = if_not_exists;
            let _ = meta;
        }
        ShowTarget::Functions {
            kind,
            from,
            filter,
            meta,
        } => {
            if let Some(item) = kind.as_ref() {
                visitor.visit_show_functions_scope(item);
            }
            if let Some(item) = from.as_ref() {
                visitor.visit_show_from(item);
            }
            if let Some(item) = filter.as_ref() {
                visitor.visit_show_functions_filter(item);
            }
            let _ = meta;
        }
        ShowTarget::RoutineStatus { kind, filter, meta } => {
            visitor.visit_show_routine_kind(kind);
            if let Some(item) = filter.as_ref() {
                visitor.visit_show_filter(item);
            }
            let _ = meta;
        }
        ShowTarget::Listing {
            kind,
            from,
            filter,
            meta,
        } => {
            visitor.visit_show_listing(kind);
            if let Some(item) = from.as_ref() {
                visitor.visit_show_from(item);
            }
            if let Some(item) = filter.as_ref() {
                visitor.visit_show_filter(item);
            }
            let _ = meta;
        }
        ShowTarget::Bare { kind, meta } => {
            visitor.visit_show_bare(kind);
            let _ = meta;
        }
        ShowTarget::Grants {
            user,
            using_roles,
            meta,
        } => {
            if let Some(item) = user.as_ref() {
                visitor.visit_account_name(item);
            }
            for item in using_roles.iter() {
                visitor.visit_account_name(item);
            }
            let _ = meta;
        }
        ShowTarget::CreateUser { user, meta } => {
            visitor.visit_account_name(user);
            let _ = meta;
        }
        ShowTarget::Profile {
            types,
            query,
            limit,
            meta,
        } => {
            for item in types.iter() {
                visitor.visit_show_profile_type(item);
            }
            if let Some(item) = query.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = limit.as_ref() {
                visitor.visit_show_limit(item);
            }
            let _ = meta;
        }
        ShowTarget::LogEvents {
            relay,
            log_name,
            position,
            limit,
            channel,
            meta,
        } => {
            let _ = relay;
            if let Some(item) = log_name.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = position.as_ref() {
                visitor.visit_literal(item);
            }
            if let Some(item) = limit.as_ref() {
                visitor.visit_show_limit(item);
            }
            if let Some(item) = channel.as_ref() {
                visitor.visit_literal(item);
            }
            let _ = meta;
        }
        ShowTarget::Index {
            spelling,
            extended,
            table,
            database,
            filter,
            meta,
        } => {
            visitor.visit_show_index_spelling(spelling);
            let _ = extended;
            visitor.visit_show_from(table);
            if let Some(item) = database.as_ref() {
                visitor.visit_show_from(item);
            }
            if let Some(item) = filter.as_ref() {
                visitor.visit_show_filter(item);
            }
            let _ = meta;
        }
        ShowTarget::Engine {
            engine,
            artifact,
            meta,
        } => {
            if let Some(item) = engine.as_ref() {
                visitor.visit_ident(item);
            }
            visitor.visit_show_engine_artifact(artifact);
            let _ = meta;
        }
        ShowTarget::ReplicaStatus { channel, meta } => {
            if let Some(item) = channel.as_ref() {
                visitor.visit_literal(item);
            }
            let _ = meta;
        }
        ShowTarget::Diagnostics {
            kind,
            count,
            limit,
            meta,
        } => {
            visitor.visit_show_diagnostic_kind(kind);
            let _ = count;
            if let Some(item) = limit.as_ref() {
                visitor.visit_show_limit(item);
            }
            let _ = meta;
        }
        ShowTarget::RoutineCode { kind, name, meta } => {
            visitor.visit_show_routine_kind(kind);
            visitor.visit_object_name(name);
            let _ = meta;
        }
    }
}
