///Walk the immediate children of a [`ShowIndexSpelling`] node.
pub fn walk_show_index_spelling<'ast, V, X>(visitor: &mut V, node: &'ast ShowIndexSpelling)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ShowIndexSpelling::Index => {}
        ShowIndexSpelling::Indexes => {}
        ShowIndexSpelling::Keys => {}
    }
}
