///Walk the immediate children of a [`ShowLimit`] node.
pub fn walk_show_limit<'ast, V, X>(visitor: &mut V, node: &'ast ShowLimit)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let ShowLimit {
        offset,
        offset_keyword,
        row_count,
        meta,
    } = node;
    if let Some(item) = offset.as_ref() {
        visitor.visit_literal(item);
    }
    let _ = offset_keyword;
    visitor.visit_literal(row_count);
    let _ = meta;
}
///Walk the immediate children of a [`WindowSpec`] node.
pub fn walk_window_spec<'ast, V, X>(visitor: &mut V, node: &'ast WindowSpec<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        WindowSpec::Named { name, meta } => {
            visitor.visit_ident(name);
            let _ = meta;
        }
        WindowSpec::Inline { definition, meta } => {
            visitor.visit_window_definition(definition);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a [`WindowDefinition`] node.
pub fn walk_window_definition<'ast, V, X>(visitor: &mut V, node: &'ast WindowDefinition<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let WindowDefinition {
        existing,
        partition_by,
        order_by,
        frame,
        meta,
    } = node;
    if let Some(item) = existing.as_ref() {
        visitor.visit_ident(item);
    }
    for item in partition_by.iter() {
        visitor.visit_expr(item);
    }
    for item in order_by.iter() {
        visitor.visit_order_by_expr(item);
    }
    if let Some(item) = frame.as_ref() {
        visitor.visit_window_frame(item);
    }
    let _ = meta;
}
///Walk the immediate children of a [`WindowFrame`] node.
pub fn walk_window_frame<'ast, V, X>(visitor: &mut V, node: &'ast WindowFrame<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let WindowFrame {
        units,
        start,
        end,
        exclusion,
        meta,
    } = node;
    visitor.visit_window_frame_units(units);
    visitor.visit_window_frame_bound(start);
    if let Some(item) = end.as_ref() {
        visitor.visit_window_frame_bound(item);
    }
    if let Some(item) = exclusion.as_ref() {
        visitor.visit_window_frame_exclusion(item);
    }
    let _ = meta;
}
///Walk the immediate children of a [`WindowFrameUnits`] node.
pub fn walk_window_frame_units<'ast, V, X>(visitor: &mut V, node: &'ast WindowFrameUnits)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        WindowFrameUnits::Rows => {}
        WindowFrameUnits::Range => {}
        WindowFrameUnits::Groups => {}
    }
}
///Walk the immediate children of a [`WindowFrameBound`] node.
pub fn walk_window_frame_bound<'ast, V, X>(visitor: &mut V, node: &'ast WindowFrameBound<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        WindowFrameBound::CurrentRow { meta } => {
            let _ = meta;
        }
        WindowFrameBound::UnboundedPreceding { meta } => {
            let _ = meta;
        }
        WindowFrameBound::UnboundedFollowing { meta } => {
            let _ = meta;
        }
        WindowFrameBound::Preceding { offset, meta } => {
            visitor.visit_expr(offset);
            let _ = meta;
        }
        WindowFrameBound::Following { offset, meta } => {
            visitor.visit_expr(offset);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a [`WindowFrameExclusion`] node.
pub fn walk_window_frame_exclusion<'ast, V, X>(visitor: &mut V, node: &'ast WindowFrameExclusion)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        WindowFrameExclusion::CurrentRow => {}
        WindowFrameExclusion::Group => {}
        WindowFrameExclusion::Ties => {}
        WindowFrameExclusion::NoOthers => {}
    }
}
///Walk the immediate children of a [`NamedWindow`] node.
pub fn walk_named_window<'ast, V, X>(visitor: &mut V, node: &'ast NamedWindow<X>)
where
    V: Visit<'ast, X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let NamedWindow {
        name,
        definition,
        meta,
    } = node;
    visitor.visit_ident(name);
    visitor.visit_window_definition(definition);
    let _ = meta;
}
