///Walk the immediate children of a mutable [`SessionStatement`] node.
pub fn walk_session_statement_mut<V, X>(visitor: &mut V, node: &mut SessionStatement<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SessionStatement::Set {
            scope,
            name,
            assignment,
            value,
            meta,
        } => {
            if let Some(item) = scope.as_mut() {
                visitor.visit_set_scope_mut(item);
            }
            visitor.visit_object_name_mut(name);
            visitor.visit_set_assignment_mut(assignment);
            visitor.visit_set_value_mut(value);
            let _ = meta;
        }
        SessionStatement::SetTimeZone { scope, value, meta } => {
            if let Some(item) = scope.as_mut() {
                visitor.visit_set_scope_mut(item);
            }
            visitor.visit_special_set_value_mut(value);
            let _ = meta;
        }
        SessionStatement::SetRole { scope, role, meta } => {
            if let Some(item) = scope.as_mut() {
                visitor.visit_set_scope_mut(item);
            }
            visitor.visit_special_set_value_mut(role);
            let _ = meta;
        }
        SessionStatement::SetSessionAuthorization { scope, user, meta } => {
            if let Some(item) = scope.as_mut() {
                visitor.visit_set_scope_mut(item);
            }
            visitor.visit_special_set_value_mut(user);
            let _ = meta;
        }
        SessionStatement::SetConstraints {
            constraints,
            check_time,
            meta,
        } => {
            visitor.visit_constraints_target_mut(constraints);
            visitor.visit_constraint_check_time_mut(check_time);
            let _ = meta;
        }
        SessionStatement::SetNames { value, meta } => {
            visitor.visit_set_names_value_mut(value);
            let _ = meta;
        }
        SessionStatement::SetSessionCharacteristics { modes, meta } => {
            for item in modes.iter_mut() {
                visitor.visit_transaction_mode_mut(item);
            }
            let _ = meta;
        }
        SessionStatement::Reset {
            scope,
            target,
            meta,
        } => {
            if let Some(item) = scope.as_mut() {
                visitor.visit_set_scope_mut(item);
            }
            visitor.visit_config_parameter_mut(target);
            let _ = meta;
        }
        SessionStatement::Show {
            target,
            verbose,
            meta,
        } => {
            visitor.visit_config_parameter_mut(target);
            let _ = verbose;
            let _ = meta;
        }
        SessionStatement::SetVariables { assignments, meta } => {
            for item in assignments.iter_mut() {
                visitor.visit_set_variable_assignment_mut(item);
            }
            let _ = meta;
        }
        SessionStatement::SetCharacterSet {
            keyword,
            value,
            meta,
        } => {
            visitor.visit_character_set_keyword_mut(keyword);
            visitor.visit_set_character_set_value_mut(value);
            let _ = meta;
        }
        SessionStatement::SetResourceGroup {
            name,
            thread_ids,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            if let Some(item) = thread_ids.as_mut() {
                for item1 in item.iter_mut() {
                    visitor.visit_literal_mut(item1);
                }
            }
            let _ = meta;
        }
    }
}
///Walk the immediate children of a mutable [`SetVariableAssignment`] node.
pub fn walk_set_variable_assignment_mut<V, X>(visitor: &mut V, node: &mut SetVariableAssignment<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SetVariableAssignment::SystemVariable {
            scope,
            name,
            assignment,
            value,
            meta,
        } => {
            visitor.visit_system_variable_scope_mut(scope);
            visitor.visit_object_name_mut(name);
            visitor.visit_set_assignment_mut(assignment);
            visitor.visit_set_variable_value_mut(value);
            let _ = meta;
        }
        SetVariableAssignment::UserVariable {
            name,
            assignment,
            value,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            visitor.visit_set_assignment_mut(assignment);
            visitor.visit_expr_mut(value);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a mutable [`SystemVariableScope`] node.
pub fn walk_system_variable_scope_mut<V, X>(visitor: &mut V, node: &mut SystemVariableScope)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SystemVariableScope::Implicit => {}
        SystemVariableScope::Keyword(field0) => {
            visitor.visit_system_variable_scope_kind_mut(field0);
        }
        SystemVariableScope::AtAt => {}
        SystemVariableScope::AtAtScoped(field0) => {
            visitor.visit_system_variable_scope_kind_mut(field0);
        }
    }
}
///Walk the immediate children of a mutable [`SystemVariableScopeKind`] node.
pub fn walk_system_variable_scope_kind_mut<V, X>(
    visitor: &mut V,
    node: &mut SystemVariableScopeKind,
) where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SystemVariableScopeKind::Global => {}
        SystemVariableScopeKind::Session => {}
        SystemVariableScopeKind::Local => {}
        SystemVariableScopeKind::Persist => {}
        SystemVariableScopeKind::PersistOnly => {}
    }
}
///Walk the immediate children of a mutable [`SetVariableValue`] node.
pub fn walk_set_variable_value_mut<V, X>(visitor: &mut V, node: &mut SetVariableValue<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SetVariableValue::Default { meta } => {
            let _ = meta;
        }
        SetVariableValue::Keyword { keyword, meta } => {
            visitor.visit_set_variable_keyword_mut(keyword);
            let _ = meta;
        }
        SetVariableValue::Expr { expr, meta } => {
            visitor.visit_expr_mut(expr);
            let _ = meta;
        }
    }
}
