///Walk the immediate children of a mutable [`AccessControlStatement`] node.
pub fn walk_access_control_statement_mut<V, X>(
    visitor: &mut V,
    node: &mut AccessControlStatement<X>,
) where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        AccessControlStatement::AlterRoleRename {
            name,
            new_name,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            visitor.visit_ident_mut(new_name);
            let _ = meta;
        }
        AccessControlStatement::Grant {
            privileges,
            object,
            grantees,
            with_grant_option,
            granted_by,
            meta,
        } => {
            visitor.visit_privileges_mut(privileges);
            visitor.visit_grant_object_mut(object);
            for item in grantees.iter_mut() {
                visitor.visit_grantee_mut(item);
            }
            let _ = with_grant_option;
            if let Some(item) = granted_by.as_mut() {
                visitor.visit_role_spec_mut(item);
            }
            let _ = meta;
        }
        AccessControlStatement::Revoke {
            grant_option_for,
            privileges,
            object,
            grantees,
            granted_by,
            behavior,
            meta,
        } => {
            let _ = grant_option_for;
            visitor.visit_privileges_mut(privileges);
            visitor.visit_grant_object_mut(object);
            for item in grantees.iter_mut() {
                visitor.visit_grantee_mut(item);
            }
            if let Some(item) = granted_by.as_mut() {
                visitor.visit_role_spec_mut(item);
            }
            if let Some(item) = behavior.as_mut() {
                visitor.visit_drop_behavior_mut(item);
            }
            let _ = meta;
        }
        AccessControlStatement::GrantRole {
            roles,
            grantees,
            with_admin_option,
            granted_by,
            meta,
        } => {
            for item in roles.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            for item in grantees.iter_mut() {
                visitor.visit_grantee_mut(item);
            }
            let _ = with_admin_option;
            if let Some(item) = granted_by.as_mut() {
                visitor.visit_role_spec_mut(item);
            }
            let _ = meta;
        }
        AccessControlStatement::RevokeRole {
            admin_option_for,
            roles,
            grantees,
            granted_by,
            behavior,
            meta,
        } => {
            let _ = admin_option_for;
            for item in roles.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            for item in grantees.iter_mut() {
                visitor.visit_grantee_mut(item);
            }
            if let Some(item) = granted_by.as_mut() {
                visitor.visit_role_spec_mut(item);
            }
            if let Some(item) = behavior.as_mut() {
                visitor.visit_drop_behavior_mut(item);
            }
            let _ = meta;
        }
        AccessControlStatement::AccountGrantPrivilege {
            privileges,
            object,
            grantees,
            with_grant_option,
            grant_as,
            meta,
        } => {
            visitor.visit_privileges_mut(privileges);
            visitor.visit_privilege_level_object_mut(object);
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = with_grant_option;
            if let Some(item) = grant_as.as_mut() {
                visitor.visit_grant_as_mut(item);
            }
            let _ = meta;
        }
        AccessControlStatement::AccountGrantProxy {
            proxy,
            grantees,
            with_grant_option,
            meta,
        } => {
            visitor.visit_account_name_mut(proxy);
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = with_grant_option;
            let _ = meta;
        }
        AccessControlStatement::AccountGrantRole {
            roles,
            grantees,
            with_admin_option,
            meta,
        } => {
            for item in roles.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = with_admin_option;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokePrivilege {
            if_exists,
            privileges,
            object,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            visitor.visit_privileges_mut(privileges);
            visitor.visit_privilege_level_object_mut(object);
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokeAll {
            if_exists,
            privileges_keyword,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            let _ = privileges_keyword;
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokeProxy {
            if_exists,
            proxy,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            visitor.visit_account_name_mut(proxy);
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
        AccessControlStatement::AccountRevokeRole {
            if_exists,
            roles,
            grantees,
            ignore_unknown_user,
            meta,
        } => {
            let _ = if_exists;
            for item in roles.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            for item in grantees.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = ignore_unknown_user;
            let _ = meta;
        }
    }
}
