///Walk the immediate children of a mutable [`CreateTable`] node.
pub fn walk_create_table_mut<V, X>(visitor: &mut V, node: &mut CreateTable<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let CreateTable {
        or_replace,
        temporary,
        unlogged,
        if_not_exists,
        name,
        body,
        inherits,
        partition_by,
        access_method,
        options,
        meta,
    } = node;
    let _ = or_replace;
    if let Some(item) = temporary.as_mut() {
        visitor.visit_temporary_table_kind_mut(item);
    }
    let _ = unlogged;
    let _ = if_not_exists;
    visitor.visit_object_name_mut(name);
    visitor.visit_create_table_body_mut(body);
    for item in inherits.iter_mut() {
        visitor.visit_object_name_mut(item);
    }
    if let Some(item) = partition_by.as_mut() {
        visitor.visit_partition_spec_mut(item);
    }
    if let Some(item) = access_method.as_mut() {
        visitor.visit_ident_mut(item);
    }
    for item in options.iter_mut() {
        visitor.visit_create_table_option_mut(item);
    }
    let _ = meta;
}
