///Walk the immediate children of a mutable [`TableConstraint`] node.
pub fn walk_table_constraint_mut<V, X>(visitor: &mut V, node: &mut TableConstraint<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TableConstraint::PrimaryKey {
            columns,
            include,
            meta,
        } => {
            for item in columns.iter_mut() {
                visitor.visit_index_column_mut(item);
            }
            for item in include.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = meta;
        }
        TableConstraint::Unique {
            columns,
            nulls_not_distinct,
            include,
            meta,
        } => {
            for item in columns.iter_mut() {
                visitor.visit_index_column_mut(item);
            }
            let _ = nulls_not_distinct;
            for item in include.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = meta;
        }
        TableConstraint::Check { expr, meta } => {
            visitor.visit_expr_mut(expr);
            let _ = meta;
        }
        TableConstraint::Exclude { exclude, meta } => {
            visitor.visit_exclude_constraint_mut(exclude);
            let _ = meta;
        }
        TableConstraint::ForeignKey {
            columns,
            references,
            meta,
        } => {
            for item in columns.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            visitor.visit_foreign_key_ref_mut(references);
            let _ = meta;
        }
        TableConstraint::Bare { meta } => {
            let _ = meta;
        }
        TableConstraint::Other { ext, meta } => {
            visitor.visit_extension_mut(ext);
            let _ = meta;
        }
    }
}
