///Walk the immediate children of a mutable [`FunctionCall`] node.
pub fn walk_function_call_mut<V, X>(visitor: &mut V, node: &mut FunctionCall<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let FunctionCall {
        name,
        quantifier,
        args,
        wildcard,
        order_by,
        within_group,
        separator,
        filter,
        filter_where,
        over,
        null_treatment,
        window_tail,
        meta,
    } = node;
    visitor.visit_object_name_mut(name);
    if let Some(item) = quantifier.as_mut() {
        visitor.visit_set_quantifier_mut(item);
    }
    for item in args.iter_mut() {
        visitor.visit_function_arg_mut(item);
    }
    let _ = wildcard;
    for item in order_by.iter_mut() {
        visitor.visit_order_by_expr_mut(item);
    }
    if let Some(item) = within_group.as_mut() {
        for item1 in item.iter_mut() {
            visitor.visit_order_by_expr_mut(item1);
        }
    }
    if let Some(item) = separator.as_mut() {
        visitor.visit_literal_mut(item);
    }
    if let Some(item) = filter.as_mut() {
        visitor.visit_expr_mut(item);
    }
    visitor.visit_filter_where_spelling_mut(filter_where);
    if let Some(item) = over.as_mut() {
        visitor.visit_window_spec_mut(item);
    }
    if let Some(item) = null_treatment.as_mut() {
        visitor.visit_null_treatment_mut(item);
    }
    if let Some(item) = window_tail.as_mut() {
        visitor.visit_window_function_tail_mut(item);
    }
    let _ = meta;
}
