///Walk the immediate children of a mutable [`XmlFunc`] node.
pub fn walk_xml_func_mut<V, X>(visitor: &mut V, node: &mut XmlFunc<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        XmlFunc::Element {
            name,
            attributes,
            content,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            for item in attributes.iter_mut() {
                visitor.visit_xml_attribute_mut(item);
            }
            for item in content.iter_mut() {
                visitor.visit_expr_mut(item);
            }
            let _ = meta;
        }
        XmlFunc::Forest { elements, meta } => {
            for item in elements.iter_mut() {
                visitor.visit_xml_attribute_mut(item);
            }
            let _ = meta;
        }
        XmlFunc::Concat { args, meta } => {
            for item in args.iter_mut() {
                visitor.visit_expr_mut(item);
            }
            let _ = meta;
        }
        XmlFunc::Parse {
            option,
            arg,
            whitespace,
            meta,
        } => {
            visitor.visit_xml_document_or_content_mut(option);
            visitor.visit_expr_mut(arg);
            visitor.visit_xml_whitespace_option_mut(whitespace);
            let _ = meta;
        }
        XmlFunc::Pi {
            name,
            content,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            if let Some(item) = content.as_mut() {
                visitor.visit_expr_mut(item);
            }
            let _ = meta;
        }
        XmlFunc::Root {
            arg,
            version,
            standalone,
            meta,
        } => {
            visitor.visit_expr_mut(arg);
            if let Some(item) = version.as_mut() {
                visitor.visit_expr_mut(item);
            }
            visitor.visit_xml_standalone_mut(standalone);
            let _ = meta;
        }
        XmlFunc::Serialize {
            option,
            arg,
            data_type,
            indent,
            meta,
        } => {
            visitor.visit_xml_document_or_content_mut(option);
            visitor.visit_expr_mut(arg);
            visitor.visit_data_type_mut(data_type);
            visitor.visit_xml_indent_option_mut(indent);
            let _ = meta;
        }
        XmlFunc::Exists {
            path,
            mechanism_before,
            arg,
            mechanism_after,
            meta,
        } => {
            visitor.visit_expr_mut(path);
            if let Some(item) = mechanism_before.as_mut() {
                visitor.visit_xml_passing_mechanism_mut(item);
            }
            visitor.visit_expr_mut(arg);
            if let Some(item) = mechanism_after.as_mut() {
                visitor.visit_xml_passing_mechanism_mut(item);
            }
            let _ = meta;
        }
    }
}
