///Walk the immediate children of a mutable [`PipeOperator`] node.
pub fn walk_pipe_operator_mut<V, X>(visitor: &mut V, node: &mut PipeOperator<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        PipeOperator::Where { predicate, meta } => {
            visitor.visit_expr_mut(predicate);
            let _ = meta;
        }
        PipeOperator::Select { items, meta } => {
            for item in items.iter_mut() {
                visitor.visit_select_item_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Extend { items, meta } => {
            for item in items.iter_mut() {
                visitor.visit_select_item_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::As { alias, meta } => {
            visitor.visit_table_alias_mut(alias);
            let _ = meta;
        }
        PipeOperator::OrderBy { keys, meta } => {
            for item in keys.iter_mut() {
                visitor.visit_order_by_expr_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Limit {
            count,
            offset,
            meta,
        } => {
            visitor.visit_expr_mut(count);
            if let Some(item) = offset.as_mut() {
                visitor.visit_expr_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Join { join, meta } => {
            visitor.visit_join_mut(join);
            let _ = meta;
        }
        PipeOperator::SetOperation {
            op,
            quantifier,
            queries,
            meta,
        } => {
            visitor.visit_set_operator_mut(op);
            if let Some(item) = quantifier.as_mut() {
                visitor.visit_set_quantifier_mut(item);
            }
            for item in queries.iter_mut() {
                visitor.visit_query_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Set { assignments, meta } => {
            for item in assignments.iter_mut() {
                visitor.visit_update_assignment_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Call { call, alias, meta } => {
            visitor.visit_function_call_mut(call);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Aggregate {
            aggregates,
            group_by,
            meta,
        } => {
            for item in aggregates.iter_mut() {
                visitor.visit_pipe_aggregate_expr_mut(item);
            }
            for item in group_by.iter_mut() {
                visitor.visit_pipe_aggregate_expr_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Drop { columns, meta } => {
            for item in columns.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Rename { renames, meta } => {
            for item in renames.iter_mut() {
                visitor.visit_pipe_rename_item_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::Pivot {
            aggregates,
            column,
            meta,
        } => {
            for item in aggregates.iter_mut() {
                visitor.visit_pivot_expr_mut(item);
            }
            visitor.visit_pivot_column_mut(column);
            let _ = meta;
        }
        PipeOperator::Unpivot {
            value,
            name,
            columns,
            meta,
        } => {
            for item in value.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            for item in name.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            for item in columns.iter_mut() {
                visitor.visit_unpivot_column_mut(item);
            }
            let _ = meta;
        }
        PipeOperator::TableSample { sample, meta } => {
            visitor.visit_table_sample_mut(sample);
            let _ = meta;
        }
    }
}
