///Walk the immediate children of a mutable [`Select`] node.
pub fn walk_select_mut<V, X>(visitor: &mut V, node: &mut Select<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let Select {
        distinct,
        straight_join,
        projection,
        into,
        from,
        lateral_views,
        selection,
        connect_by,
        group_by,
        group_by_quantifier,
        group_by_all,
        having,
        windows,
        qualify,
        sample,
        spelling,
        meta,
    } = node;
    if let Some(item) = distinct.as_mut() {
        visitor.visit_select_distinct_mut(item);
    }
    let _ = straight_join;
    for item in projection.iter_mut() {
        visitor.visit_select_item_mut(item);
    }
    if let Some(item) = into.as_mut() {
        visitor.visit_into_target_mut(item);
    }
    for item in from.iter_mut() {
        visitor.visit_table_with_joins_mut(item);
    }
    for item in lateral_views.iter_mut() {
        visitor.visit_lateral_view_mut(item);
    }
    if let Some(item) = selection.as_mut() {
        visitor.visit_expr_mut(item);
    }
    if let Some(item) = connect_by.as_mut() {
        visitor.visit_hierarchical_clause_mut(item);
    }
    for item in group_by.iter_mut() {
        visitor.visit_group_by_item_mut(item);
    }
    if let Some(item) = group_by_quantifier.as_mut() {
        visitor.visit_set_quantifier_mut(item);
    }
    if let Some(item) = group_by_all.as_mut() {
        visitor.visit_group_by_all_spelling_mut(item);
    }
    if let Some(item) = having.as_mut() {
        visitor.visit_expr_mut(item);
    }
    for item in windows.iter_mut() {
        visitor.visit_named_window_mut(item);
    }
    if let Some(item) = qualify.as_mut() {
        visitor.visit_expr_mut(item);
    }
    if let Some(item) = sample.as_mut() {
        visitor.visit_sample_clause_mut(item);
    }
    visitor.visit_select_spelling_mut(spelling);
    let _ = meta;
}
