///Walk the immediate children of a mutable [`SelectItem`] node.
pub fn walk_select_item_mut<V, X>(visitor: &mut V, node: &mut SelectItem<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        SelectItem::Wildcard {
            options,
            alias,
            alias_spelling,
            meta,
        } => {
            if let Some(item) = options.as_mut() {
                visitor.visit_wildcard_options_mut(item);
            }
            if let Some(item) = alias.as_mut() {
                visitor.visit_ident_mut(item);
            }
            visitor.visit_alias_spelling_mut(alias_spelling);
            let _ = meta;
        }
        SelectItem::QualifiedWildcard {
            name,
            options,
            alias,
            alias_spelling,
            meta,
        } => {
            visitor.visit_object_name_mut(name);
            if let Some(item) = options.as_mut() {
                visitor.visit_wildcard_options_mut(item);
            }
            if let Some(item) = alias.as_mut() {
                visitor.visit_ident_mut(item);
            }
            visitor.visit_alias_spelling_mut(alias_spelling);
            let _ = meta;
        }
        SelectItem::Expr {
            expr,
            alias,
            alias_spelling,
            meta,
        } => {
            visitor.visit_expr_mut(expr);
            if let Some(item) = alias.as_mut() {
                visitor.visit_ident_mut(item);
            }
            visitor.visit_alias_spelling_mut(alias_spelling);
            let _ = meta;
        }
    }
}
