///Walk the immediate children of a mutable [`TableHint`] node.
pub fn walk_table_hint_mut<V, X>(visitor: &mut V, node: &mut TableHint)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TableHint::Keyword { keyword, meta } => {
            visitor.visit_table_hint_keyword_mut(keyword);
            let _ = meta;
        }
        TableHint::Index {
            equals,
            indexes,
            meta,
        } => {
            let _ = equals;
            for item in indexes.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = meta;
        }
        TableHint::ForceSeek { target, meta } => {
            if let Some(item) = target.as_mut() {
                visitor.visit_force_seek_target_mut(item);
            }
            let _ = meta;
        }
        TableHint::Other { ident, meta } => {
            visitor.visit_ident_mut(ident);
            let _ = meta;
        }
    }
}
