///Walk the immediate children of a mutable [`TableFactor`] node.
pub fn walk_table_factor_mut<V, X>(visitor: &mut V, node: &mut TableFactor<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TableFactor::Table {
            name,
            inheritance,
            json_path,
            version,
            partition,
            alias,
            indexed_by,
            index_hints,
            sample,
            table_hints,
            meta,
        } => {
            visitor.visit_object_name_mut(name);
            visitor.visit_relation_inheritance_mut(inheritance);
            for item in json_path.iter_mut() {
                visitor.visit_semi_structured_path_segment_mut(item);
            }
            if let Some(item) = version.as_mut() {
                visitor.visit_table_version_mut(item);
            }
            for item in partition.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            if let Some(item) = indexed_by.as_mut() {
                visitor.visit_indexed_by_mut(item);
            }
            for item in index_hints.iter_mut() {
                visitor.visit_index_hint_mut(item);
            }
            if let Some(item) = sample.as_mut() {
                visitor.visit_table_sample_mut(item);
            }
            for item in table_hints.iter_mut() {
                visitor.visit_table_hint_mut(item);
            }
            let _ = meta;
        }
        TableFactor::Derived {
            lateral,
            subquery,
            alias,
            spelling,
            meta,
        } => {
            let _ = lateral;
            visitor.visit_query_mut(subquery);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            visitor.visit_derived_spelling_mut(spelling);
            let _ = meta;
        }
        TableFactor::Function {
            lateral,
            function,
            with_ordinality,
            alias,
            column_defs,
            meta,
        } => {
            let _ = lateral;
            visitor.visit_function_call_mut(function);
            let _ = with_ordinality;
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            for item in column_defs.iter_mut() {
                visitor.visit_table_function_column_mut(item);
            }
            let _ = meta;
        }
        TableFactor::RowsFrom {
            lateral,
            functions,
            with_ordinality,
            alias,
            meta,
        } => {
            let _ = lateral;
            for item in functions.iter_mut() {
                visitor.visit_rows_from_item_mut(item);
            }
            let _ = with_ordinality;
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::Unnest {
            lateral,
            array_exprs,
            with_ordinality,
            alias,
            column_defs,
            with_offset,
            with_offset_alias,
            meta,
        } => {
            let _ = lateral;
            for item in array_exprs.iter_mut() {
                visitor.visit_expr_mut(item);
            }
            let _ = with_ordinality;
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            for item in column_defs.iter_mut() {
                visitor.visit_table_function_column_mut(item);
            }
            let _ = with_offset;
            if let Some(item) = with_offset_alias.as_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = meta;
        }
        TableFactor::NestedJoin { table, alias, meta } => {
            visitor.visit_table_with_joins_mut(table);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::SpecialFunction {
            keyword,
            precision,
            alias,
            meta,
        } => {
            visitor.visit_special_function_keyword_mut(keyword);
            let _ = precision;
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::Pivot { pivot, alias, meta } => {
            visitor.visit_pivot_mut(pivot);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::Unpivot {
            unpivot,
            alias,
            meta,
        } => {
            visitor.visit_unpivot_mut(unpivot);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::MatchRecognize {
            match_recognize,
            alias,
            meta,
        } => {
            visitor.visit_match_recognize_mut(match_recognize);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::ShowRef { show, alias, meta } => {
            visitor.visit_show_ref_mut(show);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::JsonTable {
            json_table,
            alias,
            meta,
        } => {
            visitor.visit_json_table_mut(json_table);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::XmlTable {
            xml_table,
            alias,
            meta,
        } => {
            visitor.visit_xml_table_mut(xml_table);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::OpenJson {
            open_json,
            alias,
            meta,
        } => {
            visitor.visit_open_json_mut(open_json);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::TableExpr { expr, alias, meta } => {
            visitor.visit_expr_mut(expr);
            if let Some(item) = alias.as_mut() {
                visitor.visit_table_alias_mut(item);
            }
            let _ = meta;
        }
        TableFactor::Other { ext, meta } => {
            visitor.visit_extension_mut(ext);
            let _ = meta;
        }
    }
}
