pub fn walk_show_ref_target_mut<V, X>(visitor: &mut V, node: &mut ShowRefTarget<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ShowRefTarget::Empty { meta } => {
            let _ = meta;
        }
        ShowRefTarget::Query { query, meta } => {
            visitor.visit_query_mut(query);
            let _ = meta;
        }
        ShowRefTarget::Name { name, meta } => {
            visitor.visit_object_name_mut(name);
            let _ = meta;
        }
    }
}
///Walk the immediate children of a mutable [`JsonTable`] node.
pub fn walk_json_table_mut<V, X>(visitor: &mut V, node: &mut JsonTable<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let JsonTable {
        lateral,
        context,
        path,
        path_name,
        passing,
        columns,
        on_error,
        meta,
    } = node;
    let _ = lateral;
    visitor.visit_json_value_expr_mut(context);
    visitor.visit_expr_mut(path);
    if let Some(item) = path_name.as_mut() {
        visitor.visit_ident_mut(item);
    }
    for item in passing.iter_mut() {
        visitor.visit_json_passing_arg_mut(item);
    }
    for item in columns.iter_mut() {
        visitor.visit_json_table_column_mut(item);
    }
    if let Some(item) = on_error.as_mut() {
        visitor.visit_json_behavior_mut(item);
    }
    let _ = meta;
}
///Walk the immediate children of a mutable [`JsonTableColumn`] node.
pub fn walk_json_table_column_mut<V, X>(visitor: &mut V, node: &mut JsonTableColumn<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        JsonTableColumn::ForOrdinality { name, meta } => {
            visitor.visit_ident_mut(name);
            let _ = meta;
        }
        JsonTableColumn::Regular {
            name,
            data_type,
            format,
            path,
            wrapper,
            quotes,
            on_empty,
            on_error,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            visitor.visit_data_type_mut(data_type);
            if let Some(item) = format.as_mut() {
                visitor.visit_json_format_mut(item);
            }
            if let Some(item) = path.as_mut() {
                visitor.visit_expr_mut(item);
            }
            visitor.visit_json_wrapper_behavior_mut(wrapper);
            visitor.visit_json_quotes_behavior_mut(quotes);
            if let Some(item) = on_empty.as_mut() {
                visitor.visit_json_behavior_mut(item);
            }
            if let Some(item) = on_error.as_mut() {
                visitor.visit_json_behavior_mut(item);
            }
            let _ = meta;
        }
        JsonTableColumn::Exists {
            name,
            data_type,
            path,
            on_error,
            meta,
        } => {
            visitor.visit_ident_mut(name);
            visitor.visit_data_type_mut(data_type);
            if let Some(item) = path.as_mut() {
                visitor.visit_expr_mut(item);
            }
            if let Some(item) = on_error.as_mut() {
                visitor.visit_json_behavior_mut(item);
            }
            let _ = meta;
        }
        JsonTableColumn::Nested {
            path,
            path_name,
            columns,
            meta,
        } => {
            visitor.visit_expr_mut(path);
            if let Some(item) = path_name.as_mut() {
                visitor.visit_ident_mut(item);
            }
            for item in columns.iter_mut() {
                visitor.visit_json_table_column_mut(item);
            }
            let _ = meta;
        }
    }
}
