///Walk the immediate children of a mutable [`CompoundStatement`] node.
pub fn walk_compound_statement_mut<V, X>(visitor: &mut V, node: &mut CompoundStatement<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let CompoundStatement {
        label,
        declarations,
        body,
        end_label,
        meta,
    } = node;
    if let Some(item) = label.as_mut() {
        visitor.visit_ident_mut(item);
    }
    for item in declarations.iter_mut() {
        visitor.visit_declaration_mut(item);
    }
    for item in body.iter_mut() {
        visitor.visit_statement_mut(item);
    }
    if let Some(item) = end_label.as_mut() {
        visitor.visit_ident_mut(item);
    }
    let _ = meta;
}
///Walk the immediate children of a mutable [`Declaration`] node.
pub fn walk_declaration_mut<V, X>(visitor: &mut V, node: &mut Declaration<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        Declaration::Variable {
            names,
            data_type,
            default,
            meta,
        } => {
            for item in names.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            visitor.visit_data_type_mut(data_type);
            if let Some(item) = default.as_mut() {
                visitor.visit_expr_mut(item);
            }
            let _ = meta;
        }
        Declaration::Condition { name, value, meta } => {
            visitor.visit_ident_mut(name);
            visitor.visit_condition_value_mut(value);
            let _ = meta;
        }
        Declaration::Cursor { name, query, meta } => {
            visitor.visit_ident_mut(name);
            visitor.visit_query_mut(query);
            let _ = meta;
        }
        Declaration::Handler {
            action,
            conditions,
            body,
            meta,
        } => {
            visitor.visit_handler_action_mut(action);
            for item in conditions.iter_mut() {
                visitor.visit_handler_condition_mut(item);
            }
            visitor.visit_statement_mut(body);
            let _ = meta;
        }
    }
}
