///Walk the immediate children of a mutable [`TransactionStatement`] node.
pub fn walk_transaction_statement_mut<V, X>(visitor: &mut V, node: &mut TransactionStatement)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TransactionStatement::Begin {
            syntax,
            mode,
            block,
            name,
            modes,
            meta,
        } => {
            visitor.visit_transaction_start_mut(syntax);
            if let Some(item) = mode.as_mut() {
                visitor.visit_transaction_mode_kind_mut(item);
            }
            if let Some(item) = block.as_mut() {
                visitor.visit_transaction_block_keyword_mut(item);
            }
            if let Some(item) = name.as_mut() {
                visitor.visit_ident_mut(item);
            }
            for item in modes.iter_mut() {
                visitor.visit_transaction_mode_mut(item);
            }
            let _ = meta;
        }
        TransactionStatement::Commit {
            syntax,
            block,
            name,
            chain,
            release,
            meta,
        } => {
            visitor.visit_transaction_commit_keyword_mut(syntax);
            if let Some(item) = block.as_mut() {
                visitor.visit_transaction_block_keyword_mut(item);
            }
            if let Some(item) = name.as_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = chain;
            let _ = release;
            let _ = meta;
        }
        TransactionStatement::Rollback {
            syntax,
            block,
            name,
            savepoint_keyword,
            to_savepoint,
            chain,
            release,
            meta,
        } => {
            visitor.visit_transaction_rollback_keyword_mut(syntax);
            if let Some(item) = block.as_mut() {
                visitor.visit_transaction_block_keyword_mut(item);
            }
            if let Some(item) = name.as_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = savepoint_keyword;
            if let Some(item) = to_savepoint.as_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = chain;
            let _ = release;
            let _ = meta;
        }
        TransactionStatement::Savepoint { name, meta } => {
            visitor.visit_ident_mut(name);
            let _ = meta;
        }
        TransactionStatement::Release {
            savepoint_keyword,
            savepoint,
            meta,
        } => {
            let _ = savepoint_keyword;
            visitor.visit_ident_mut(savepoint);
            let _ = meta;
        }
        TransactionStatement::SetCharacteristics { modes, meta } => {
            for item in modes.iter_mut() {
                visitor.visit_transaction_mode_mut(item);
            }
            let _ = meta;
        }
    }
}
