///Walk the immediate children of a mutable [`XaStatement`] node.
pub fn walk_xa_statement_mut<V, X>(visitor: &mut V, node: &mut XaStatement)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        XaStatement::Start {
            keyword,
            xid,
            association,
            meta,
        } => {
            visitor.visit_xa_start_keyword_mut(keyword);
            visitor.visit_xid_mut(xid);
            if let Some(item) = association.as_mut() {
                visitor.visit_xa_association_mut(item);
            }
            let _ = meta;
        }
        XaStatement::End { xid, suspend, meta } => {
            visitor.visit_xid_mut(xid);
            if let Some(item) = suspend.as_mut() {
                visitor.visit_xa_suspend_mut(item);
            }
            let _ = meta;
        }
        XaStatement::Prepare { xid, meta } => {
            visitor.visit_xid_mut(xid);
            let _ = meta;
        }
        XaStatement::Commit {
            xid,
            one_phase,
            meta,
        } => {
            visitor.visit_xid_mut(xid);
            let _ = one_phase;
            let _ = meta;
        }
        XaStatement::Rollback { xid, meta } => {
            visitor.visit_xid_mut(xid);
            let _ = meta;
        }
        XaStatement::Recover { convert_xid, meta } => {
            let _ = convert_xid;
            let _ = meta;
        }
    }
}
