///Walk the immediate children of a mutable [`DataType`] node.
pub fn walk_data_type_mut<V, X>(visitor: &mut V, node: &mut DataType<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        DataType::Boolean { spelling, meta } => {
            visitor.visit_boolean_type_name_mut(spelling);
            let _ = meta;
        }
        DataType::TinyInt {
            display_width,
            meta,
        } => {
            let _ = display_width;
            let _ = meta;
        }
        DataType::SmallInt {
            display_width,
            meta,
        } => {
            let _ = display_width;
            let _ = meta;
        }
        DataType::MediumInt {
            display_width,
            meta,
        } => {
            let _ = display_width;
            let _ = meta;
        }
        DataType::Integer {
            spelling,
            display_width,
            meta,
        } => {
            visitor.visit_integer_type_name_mut(spelling);
            let _ = display_width;
            let _ = meta;
        }
        DataType::BigInt {
            display_width,
            meta,
        } => {
            let _ = display_width;
            let _ = meta;
        }
        DataType::Decimal {
            spelling,
            precision,
            scale,
            meta,
        } => {
            visitor.visit_decimal_type_name_mut(spelling);
            let _ = precision;
            let _ = scale;
            let _ = meta;
        }
        DataType::Float { precision, meta } => {
            let _ = precision;
            let _ = meta;
        }
        DataType::Real { meta } => {
            let _ = meta;
        }
        DataType::Double { spelling, meta } => {
            visitor.visit_double_type_name_mut(spelling);
            let _ = meta;
        }
        DataType::Text {
            spelling,
            charset,
            meta,
        } => {
            visitor.visit_text_type_name_mut(spelling);
            if let Some(item) = charset.as_mut() {
                visitor.visit_charset_annotation_mut(item);
            }
            let _ = meta;
        }
        DataType::Blob { spelling, meta } => {
            visitor.visit_blob_type_name_mut(spelling);
            let _ = meta;
        }
        DataType::Character {
            spelling,
            size,
            charset,
            meta,
        } => {
            visitor.visit_character_type_name_mut(spelling);
            let _ = size;
            if let Some(item) = charset.as_mut() {
                visitor.visit_charset_annotation_mut(item);
            }
            let _ = meta;
        }
        DataType::Binary {
            spelling,
            size,
            meta,
        } => {
            visitor.visit_binary_type_name_mut(spelling);
            let _ = size;
            let _ = meta;
        }
        DataType::Bit {
            varying,
            size,
            meta,
        } => {
            let _ = varying;
            let _ = size;
            let _ = meta;
        }
        DataType::Json { meta } => {
            let _ = meta;
        }
        DataType::Uuid { meta } => {
            let _ = meta;
        }
        DataType::Date { meta } => {
            let _ = meta;
        }
        DataType::Time {
            spelling,
            precision,
            time_zone,
            meta,
        } => {
            visitor.visit_time_type_name_mut(spelling);
            let _ = precision;
            visitor.visit_time_zone_mut(time_zone);
            let _ = meta;
        }
        DataType::Timestamp {
            spelling,
            precision,
            time_zone,
            meta,
        } => {
            visitor.visit_timestamp_type_name_mut(spelling);
            let _ = precision;
            visitor.visit_time_zone_mut(time_zone);
            let _ = meta;
        }
        DataType::Interval {
            fields,
            precision,
            meta,
        } => {
            if let Some(item) = fields.as_mut() {
                visitor.visit_interval_fields_mut(item);
            }
            let _ = precision;
            let _ = meta;
        }
        DataType::Enum {
            values,
            charset,
            meta,
        } => {
            for item in values.iter_mut() {
                visitor.visit_literal_mut(item);
            }
            if let Some(item) = charset.as_mut() {
                visitor.visit_charset_annotation_mut(item);
            }
            let _ = meta;
        }
        DataType::Set {
            values,
            charset,
            meta,
        } => {
            for item in values.iter_mut() {
                visitor.visit_literal_mut(item);
            }
            if let Some(item) = charset.as_mut() {
                visitor.visit_charset_annotation_mut(item);
            }
            let _ = meta;
        }
        DataType::NumericModifier {
            element,
            signedness,
            zerofill,
            meta,
        } => {
            if let Some(item) = element.as_mut() {
                visitor.visit_data_type_mut(item);
            }
            visitor.visit_signedness_mut(signedness);
            let _ = zerofill;
            let _ = meta;
        }
        DataType::Array {
            element,
            size,
            spelling,
            meta,
        } => {
            visitor.visit_data_type_mut(element);
            let _ = size;
            visitor.visit_array_type_spelling_mut(spelling);
            let _ = meta;
        }
        DataType::Struct {
            fields,
            spelling,
            meta,
        } => {
            for item in fields.iter_mut() {
                visitor.visit_struct_type_field_mut(item);
            }
            visitor.visit_struct_type_spelling_mut(spelling);
            let _ = meta;
        }
        DataType::Union { members, meta } => {
            for item in members.iter_mut() {
                visitor.visit_struct_type_field_mut(item);
            }
            let _ = meta;
        }
        DataType::Map { key, value, meta } => {
            visitor.visit_data_type_mut(key);
            visitor.visit_data_type_mut(value);
            let _ = meta;
        }
        DataType::Wrapped { kind, inner, meta } => {
            visitor.visit_wrapped_type_kind_mut(kind);
            visitor.visit_data_type_mut(inner);
            let _ = meta;
        }
        DataType::FixedString { length, meta } => {
            let _ = length;
            let _ = meta;
        }
        DataType::DateTime64 {
            precision,
            timezone,
            meta,
        } => {
            let _ = precision;
            if let Some(item) = timezone.as_mut() {
                visitor.visit_literal_mut(item);
            }
            let _ = meta;
        }
        DataType::Nested { fields, meta } => {
            for item in fields.iter_mut() {
                visitor.visit_struct_type_field_mut(item);
            }
            let _ = meta;
        }
        DataType::FixedWidthInt {
            signed,
            width,
            meta,
        } => {
            let _ = signed;
            visitor.visit_int_width_mut(width);
            let _ = meta;
        }
        DataType::UserDefined {
            name,
            modifiers,
            meta,
        } => {
            visitor.visit_object_name_mut(name);
            for item in modifiers.iter_mut() {
                visitor.visit_literal_mut(item);
            }
            let _ = meta;
        }
        DataType::Liberal { words, args, meta } => {
            for item in words.iter_mut() {
                visitor.visit_ident_mut(item);
            }
            let _ = args;
            let _ = meta;
        }
        DataType::Other { ext, meta } => {
            visitor.visit_extension_mut(ext);
            let _ = meta;
        }
    }
}
