///Walk the immediate children of a mutable [`TableMaintenanceKind`] node.
pub fn walk_table_maintenance_kind_mut<V, X>(visitor: &mut V, node: &mut TableMaintenanceKind)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        TableMaintenanceKind::Analyze {
            no_write_to_binlog,
            histogram,
            meta,
        } => {
            if let Some(item) = no_write_to_binlog.as_mut() {
                visitor.visit_no_write_to_binlog_mut(item);
            }
            if let Some(item) = histogram.as_mut() {
                visitor.visit_analyze_histogram_mut(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Check { options, meta } => {
            for item in options.iter_mut() {
                visitor.visit_check_table_option_mut(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Checksum { option, meta } => {
            if let Some(item) = option.as_mut() {
                visitor.visit_checksum_table_option_mut(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Optimize {
            no_write_to_binlog,
            meta,
        } => {
            if let Some(item) = no_write_to_binlog.as_mut() {
                visitor.visit_no_write_to_binlog_mut(item);
            }
            let _ = meta;
        }
        TableMaintenanceKind::Repair {
            no_write_to_binlog,
            options,
            meta,
        } => {
            if let Some(item) = no_write_to_binlog.as_mut() {
                visitor.visit_no_write_to_binlog_mut(item);
            }
            for item in options.iter_mut() {
                visitor.visit_repair_table_option_mut(item);
            }
            let _ = meta;
        }
    }
}
