///Walk the immediate children of a mutable [`LoadDataStatement`] node.
pub fn walk_load_data_statement_mut<V, X>(visitor: &mut V, node: &mut LoadDataStatement<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    let LoadDataStatement {
        format,
        concurrency,
        local,
        file,
        on_duplicate,
        table,
        partitions,
        charset,
        rows_identified_by,
        fields,
        lines,
        ignore_rows,
        columns,
        set,
        meta,
    } = node;
    visitor.visit_load_data_format_mut(format);
    if let Some(item) = concurrency.as_mut() {
        visitor.visit_load_data_concurrency_mut(item);
    }
    let _ = local;
    visitor.visit_literal_mut(file);
    if let Some(item) = on_duplicate.as_mut() {
        visitor.visit_load_data_duplicate_mut(item);
    }
    visitor.visit_object_name_mut(table);
    for item in partitions.iter_mut() {
        visitor.visit_ident_mut(item);
    }
    if let Some(item) = charset.as_mut() {
        visitor.visit_ident_mut(item);
    }
    if let Some(item) = rows_identified_by.as_mut() {
        visitor.visit_literal_mut(item);
    }
    if let Some(item) = fields.as_mut() {
        visitor.visit_load_data_fields_mut(item);
    }
    if let Some(item) = lines.as_mut() {
        visitor.visit_load_data_lines_mut(item);
    }
    if let Some(item) = ignore_rows.as_mut() {
        visitor.visit_load_data_ignore_rows_mut(item);
    }
    for item in columns.iter_mut() {
        visitor.visit_load_data_field_or_var_mut(item);
    }
    for item in set.iter_mut() {
        visitor.visit_update_assignment_mut(item);
    }
    let _ = meta;
}
