///Walk the immediate children of a mutable [`ShowTarget`] node.
pub fn walk_show_target_mut<V, X>(visitor: &mut V, node: &mut ShowTarget<X>)
where
    V: VisitMut<X> + ?Sized,
    X: Extension,
{
    let _ = &mut *visitor;
    match node {
        ShowTarget::Tables {
            extended,
            full,
            all,
            from,
            filter,
            meta,
        } => {
            let _ = extended;
            let _ = full;
            let _ = all;
            if let Some(item) = from.as_mut() {
                visitor.visit_show_from_mut(item);
            }
            if let Some(item) = filter.as_mut() {
                visitor.visit_show_filter_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Columns {
            extended,
            full,
            spelling,
            table,
            database,
            filter,
            meta,
        } => {
            let _ = extended;
            let _ = full;
            visitor.visit_show_columns_spelling_mut(spelling);
            visitor.visit_show_from_mut(table);
            if let Some(item) = database.as_mut() {
                visitor.visit_show_from_mut(item);
            }
            if let Some(item) = filter.as_mut() {
                visitor.visit_show_filter_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Create {
            kind,
            name,
            if_not_exists,
            meta,
        } => {
            visitor.visit_show_create_kind_mut(kind);
            visitor.visit_object_name_mut(name);
            let _ = if_not_exists;
            let _ = meta;
        }
        ShowTarget::Functions {
            kind,
            from,
            filter,
            meta,
        } => {
            if let Some(item) = kind.as_mut() {
                visitor.visit_show_functions_scope_mut(item);
            }
            if let Some(item) = from.as_mut() {
                visitor.visit_show_from_mut(item);
            }
            if let Some(item) = filter.as_mut() {
                visitor.visit_show_functions_filter_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::RoutineStatus { kind, filter, meta } => {
            visitor.visit_show_routine_kind_mut(kind);
            if let Some(item) = filter.as_mut() {
                visitor.visit_show_filter_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Listing {
            kind,
            from,
            filter,
            meta,
        } => {
            visitor.visit_show_listing_mut(kind);
            if let Some(item) = from.as_mut() {
                visitor.visit_show_from_mut(item);
            }
            if let Some(item) = filter.as_mut() {
                visitor.visit_show_filter_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Bare { kind, meta } => {
            visitor.visit_show_bare_mut(kind);
            let _ = meta;
        }
        ShowTarget::Grants {
            user,
            using_roles,
            meta,
        } => {
            if let Some(item) = user.as_mut() {
                visitor.visit_account_name_mut(item);
            }
            for item in using_roles.iter_mut() {
                visitor.visit_account_name_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::CreateUser { user, meta } => {
            visitor.visit_account_name_mut(user);
            let _ = meta;
        }
        ShowTarget::Profile {
            types,
            query,
            limit,
            meta,
        } => {
            for item in types.iter_mut() {
                visitor.visit_show_profile_type_mut(item);
            }
            if let Some(item) = query.as_mut() {
                visitor.visit_literal_mut(item);
            }
            if let Some(item) = limit.as_mut() {
                visitor.visit_show_limit_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::LogEvents {
            relay,
            log_name,
            position,
            limit,
            channel,
            meta,
        } => {
            let _ = relay;
            if let Some(item) = log_name.as_mut() {
                visitor.visit_literal_mut(item);
            }
            if let Some(item) = position.as_mut() {
                visitor.visit_literal_mut(item);
            }
            if let Some(item) = limit.as_mut() {
                visitor.visit_show_limit_mut(item);
            }
            if let Some(item) = channel.as_mut() {
                visitor.visit_literal_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Index {
            spelling,
            extended,
            table,
            database,
            filter,
            meta,
        } => {
            visitor.visit_show_index_spelling_mut(spelling);
            let _ = extended;
            visitor.visit_show_from_mut(table);
            if let Some(item) = database.as_mut() {
                visitor.visit_show_from_mut(item);
            }
            if let Some(item) = filter.as_mut() {
                visitor.visit_show_filter_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Engine {
            engine,
            artifact,
            meta,
        } => {
            if let Some(item) = engine.as_mut() {
                visitor.visit_ident_mut(item);
            }
            visitor.visit_show_engine_artifact_mut(artifact);
            let _ = meta;
        }
        ShowTarget::ReplicaStatus { channel, meta } => {
            if let Some(item) = channel.as_mut() {
                visitor.visit_literal_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::Diagnostics {
            kind,
            count,
            limit,
            meta,
        } => {
            visitor.visit_show_diagnostic_kind_mut(kind);
            let _ = count;
            if let Some(item) = limit.as_mut() {
                visitor.visit_show_limit_mut(item);
            }
            let _ = meta;
        }
        ShowTarget::RoutineCode { kind, name, meta } => {
            visitor.visit_show_routine_kind_mut(kind);
            visitor.visit_object_name_mut(name);
            let _ = meta;
        }
    }
}
